import { useEffect, useRef } from 'react';

const certs = [
  {
    icon: 'ri-award-fill',
    iconColor: 'text-teal-600',
    iconBg: 'bg-teal-50 border-teal-200',
    name: 'GS 1등급',
    sub: 'Good Software 인증',
  },
  {
    icon: 'ri-shield-check-fill',
    iconColor: 'text-gray-700',
    iconBg: 'bg-gray-50 border-gray-200',
    name: 'ISO 27001',
    sub: '정보보호 인증',
  },
  {
    icon: 'ri-file-paper-2-fill',
    iconColor: 'text-orange-500',
    iconBg: 'bg-orange-50 border-orange-200',
    name: '특허 보유',
    sub: '다수 보안 기술 특허',
  },
  {
    icon: 'ri-trophy-fill',
    iconColor: 'text-yellow-500',
    iconBg: 'bg-yellow-50 border-yellow-200',
    name: '수상 경력',
    sub: '다수 보안 대상 수상',
  },
];

export default function Certifications() {
  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('opacity-100', 'translate-y-0');
            entry.target.classList.remove('opacity-0', 'translate-y-5');
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.05, rootMargin: '0px 0px -20px 0px' }
    );
    cardRefs.current.forEach((el) => {
      if (!el) return;
      const rect = el.getBoundingClientRect();
      if (rect.top < window.innerHeight && rect.bottom > 0) {
        el.classList.add('opacity-100', 'translate-y-0');
        el.classList.remove('opacity-0', 'translate-y-5');
      } else {
        observer.observe(el);
      }
    });
    return () => observer.disconnect();
  }, []);

  return (
    <section className="py-7 bg-white">
      <div className="max-w-content mx-auto px-6 lg:px-8">
        <div className="text-center mb-8">
          <h2 className="text-3xl md:text-4xl font-black text-gray-900 mb-4">검증된 전문성</h2>
          <p className="text-base text-gray-500 max-w-xl mx-auto">
            국가 공인 인증과 수상 실적으로 증명된 스틸리언의 기술력과 신뢰성.
          </p>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-5">
          {certs.map((c, i) => (
            <div
              key={i}
              ref={(el) => { cardRefs.current[i] = el; }}
              className="opacity-0 translate-y-5 transition-all duration-600 bg-white border border-gray-100 rounded-2xl p-6 text-center hover:border-teal-200 hover:shadow-md"
              style={{ transitionDelay: `${i * 100}ms` }}
            >
              <div className={`w-12 h-12 flex items-center justify-center rounded-xl border mx-auto mb-4 ${c.iconBg}`}>
                <i className={`${c.icon} text-2xl ${c.iconColor}`}></i>
              </div>
              <div className="text-base font-black text-gray-900 mb-1">{c.name}</div>
              <div className="text-xs text-gray-500">{c.sub}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
