import { useState, useMemo } from 'react';
import { MEMBERS, DEPARTMENTS, PERMISSIONS } from '../mockData';
import type { Member } from '../types';

type MemberTab = 'members' | 'depts' | 'perms';
type DeptFilter = '전체' | '솔루션' | '컨설팅' | 'R&D' | '경영전략' | '일본' | '인니';

const PERM_KEYS = ['STADM', 'Supvr', 'Editor', 'GrdA', 'GrdB', 'GrdC', 'GrdD'] as const;
type PermKey = typeof PERM_KEYS[number];

const PERM_LABELS: Record<PermKey, string> = { STADM: 'STADM', Supvr: 'Supvr', Editor: 'Editor', GrdA: 'Grd A', GrdB: 'Grd B', GrdC: 'Grd C', GrdD: 'Grd D' };

function UserModal({ member, onClose, onSave, onDelete }: { member: Member | null; onClose: () => void; onSave: (m: Member) => void; onDelete?: (id: number) => void }) {
  const isNew = !member;
  const [form, setForm] = useState<Member>(member ?? {
    id: Date.now(), empno: '', name: '', dept: '', email: '', joinDate: '', leaveDate: '—', lang: 'KR', roles: { STADM: false, Supvr: false, Editor: false, GrdA: false, GrdB: false, GrdC: false, GrdD: false }, active: true,
  });

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />
      <div className="relative bg-white rounded-xl w-[500px] max-h-[90vh] flex flex-col" style={{ maxWidth: '95vw' }}>
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <span className="text-[14px] font-bold text-gray-900">{isNew ? '신규 추가' : '유저 수정'}</span>
          <button onClick={onClose} className="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-gray-100 cursor-pointer">
            <i className="ri-close-line text-gray-500 text-lg"></i>
          </button>
        </div>
        <div className="overflow-y-auto px-6 py-5 space-y-4">
          <div className="grid grid-cols-2 gap-3">
            {([['사번', 'empno'], ['이름', 'name'], ['부서명', 'dept'], ['이메일 (@ 앞)', 'email'], ['입사일 (YYMMDD)', 'joinDate'], ['퇴사일', 'leaveDate'], ['담당 언어', 'lang']] as [string, keyof Member][]).map(([label, key]) => (
              <div key={String(key)}>
                <label className="text-[11px] text-gray-500 mb-1 block">{label}</label>
                <input value={String(form[key])} onChange={(e) => setForm({ ...form, [key]: e.target.value })} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400" />
              </div>
            ))}
          </div>
          <div>
            <p className="text-[11px] text-gray-500 mb-2">권한 등급 (복수 선택 가능)</p>
            <div className="flex flex-wrap gap-2">
              {PERM_KEYS.map((k) => (
                <label key={k} className="flex items-center gap-1.5 cursor-pointer">
                  <input type="checkbox" checked={form.roles[k]} onChange={(e) => setForm({ ...form, roles: { ...form.roles, [k]: e.target.checked } })} className="rounded" />
                  <span className="text-[12px] text-gray-700">{PERM_LABELS[k]}</span>
                </label>
              ))}
            </div>
          </div>
          <div>
            <label className="flex items-center gap-2 cursor-pointer">
              <input type="checkbox" checked={form.active} onChange={(e) => setForm({ ...form, active: e.target.checked })} className="rounded" />
              <span className="text-[12px] text-gray-700">활성 상태</span>
            </label>
          </div>
        </div>
        <div className="flex items-center justify-between px-6 py-3.5 border-t border-gray-100">
          <div>
            {!isNew && onDelete && (
              <button onClick={() => { onDelete(form.id); onClose(); }} className="px-3 py-1.5 rounded-lg border border-rose-200 text-rose-500 text-[12px] hover:bg-rose-50 transition-colors cursor-pointer whitespace-nowrap">삭제</button>
            )}
          </div>
          <div className="flex gap-2">
            <button onClick={onClose} className="px-4 py-1.5 rounded-lg border border-gray-200 text-[12px] text-gray-600 hover:bg-gray-50 cursor-pointer whitespace-nowrap">취소</button>
            <button onClick={() => onSave(form)} className="px-4 py-1.5 rounded-lg bg-teal-500 text-white text-[12px] font-semibold hover:bg-teal-600 cursor-pointer whitespace-nowrap">저장</button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function MemberPage() {
  const [tab, setTab] = useState<MemberTab>('members');
  const [deptFilter, setDeptFilter] = useState<DeptFilter>('전체');
  const [search, setSearch] = useState('');
  const [members, setMembers] = useState<Member[]>(MEMBERS);
  const [modalMember, setModalMember] = useState<Member | null | undefined>(undefined);

  const filteredMembers = useMemo(() => {
    let list = members;
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter((m) => m.name.toLowerCase().includes(q) || m.dept.toLowerCase().includes(q) || m.email.toLowerCase().includes(q));
    }
    return list;
  }, [members, search]);

  const filteredDepts = deptFilter === '전체' ? DEPARTMENTS : DEPARTMENTS.filter((d) => d.name === deptFilter || d.name.startsWith(deptFilter));

  const handleSave = (m: Member) => {
    setMembers((prev) => prev.some((x) => x.id === m.id) ? prev.map((x) => x.id === m.id ? m : x) : [...prev, m]);
    setModalMember(undefined);
  };
  const handleDelete = (id: number) => setMembers((prev) => prev.filter((x) => x.id !== id));

  return (
    <div className="p-5 space-y-4">
      {/* Tab bar */}
      <div className="bg-white border border-gray-100 rounded-lg px-4 py-3 flex items-center justify-between flex-wrap gap-3">
        <div className="flex gap-1">
          {([['members', '회원'], ['depts', '부서'], ['perms', '권한']] as [MemberTab, string][]).map(([id, label]) => (
            <button key={id} onClick={() => setTab(id)} className={`px-3 py-1.5 rounded-lg text-[12px] font-medium transition-colors cursor-pointer whitespace-nowrap ${tab === id ? 'bg-[#1a1e2a] text-white' : 'text-gray-500 hover:bg-gray-100'}`}>{label}</button>
          ))}
        </div>
        <div className="flex items-center gap-2">
          {tab === 'members' && (
            <div className="flex items-center gap-1.5 border border-gray-200 rounded-lg px-3 py-1.5">
              <i className="ri-search-line text-gray-400 text-sm"></i>
              <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="이름, 부서, 이메일" className="text-[12px] text-gray-700 outline-none w-32 placeholder:text-gray-300" />
            </div>
          )}
          <button onClick={() => setModalMember(null)} className="flex items-center gap-1.5 px-3 py-1.5 bg-teal-500 text-white text-[12px] font-semibold rounded-lg hover:bg-teal-600 transition-colors cursor-pointer whitespace-nowrap">
            <i className="ri-add-line text-sm"></i>신규 추가
          </button>
        </div>
      </div>

      {/* Stats bar */}
      {tab === 'members' && (
        <div className="bg-white border border-gray-100 rounded-lg px-5 py-2.5 flex items-center gap-5 text-[12px] text-gray-500">
          <span>총 <strong className="text-gray-900">{filteredMembers.length}</strong>명</span>
          <span>활성 <strong className="text-teal-500">{filteredMembers.filter((m) => m.active).length}</strong>명</span>
          <span>비활성 <strong className="text-gray-400">{filteredMembers.filter((m) => !m.active).length}</strong>명</span>
        </div>
      )}

      {/* Members table */}
      {tab === 'members' && (
        <div className="bg-white border border-gray-100 rounded-lg overflow-x-auto">
          <table className="w-full" style={{ minWidth: 900 }}>
            <thead>
              <tr className="bg-gray-50/70 border-b border-gray-100">
                {['사번', '이름', '부서명', '이메일', '입사', '퇴사', '언어', ...PERM_KEYS.map((k) => PERM_LABELS[k]), '관리', '활성'].map((h) => (
                  <th key={h} className="text-left px-3 py-2.5 text-[10px] font-semibold text-gray-400 whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filteredMembers.map((m) => (
                <tr key={m.id} className="border-b border-gray-50 hover:bg-gray-50/60 transition-colors">
                  <td className="px-3 py-2.5 text-[11px] font-mono text-gray-500 cursor-pointer text-teal-600 whitespace-nowrap" onClick={() => setModalMember(m)}>{m.empno}</td>
                  <td className="px-3 py-2.5 text-[12px] font-medium text-gray-800 cursor-pointer whitespace-nowrap" onClick={() => setModalMember(m)}>{m.name}</td>
                  <td className="px-3 py-2.5 text-[12px] text-gray-600 whitespace-nowrap">{m.dept}</td>
                  <td className="px-3 py-2.5 text-[11px] font-mono text-gray-500 whitespace-nowrap">{m.email}</td>
                  <td className="px-3 py-2.5 text-[11px] font-mono text-gray-500 whitespace-nowrap">{m.joinDate}</td>
                  <td className="px-3 py-2.5 text-[11px] font-mono text-gray-400 whitespace-nowrap">{m.leaveDate}</td>
                  <td className="px-3 py-2.5 text-[11px] text-gray-500 whitespace-nowrap">{m.lang}</td>
                  {PERM_KEYS.map((k) => (
                    <td key={k} className="px-3 py-2.5">
                      <span className={`w-2 h-2 rounded-full inline-block ${m.roles[k] ? 'bg-teal-500' : 'bg-gray-200'}`}></span>
                    </td>
                  ))}
                  <td className="px-3 py-2.5">
                    <button onClick={() => setModalMember(m)} className="text-[11px] text-teal-600 hover:text-teal-700 cursor-pointer whitespace-nowrap">수정</button>
                  </td>
                  <td className="px-3 py-2.5">
                    <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full whitespace-nowrap ${m.active ? 'bg-teal-50 text-teal-700' : 'bg-gray-100 text-gray-500'}`}>{m.active ? '활성' : '비활성'}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Depts tab */}
      {tab === 'depts' && (
        <div className="space-y-4">
          <div className="bg-white border border-gray-100 rounded-lg px-4 py-3 flex gap-1 flex-wrap">
            {(['전체', '솔루션', '컨설팅', 'R&D', '경영전략', '일본', '인니'] as DeptFilter[]).map((d) => (
              <button key={d} onClick={() => setDeptFilter(d)} className={`px-3 py-1.5 rounded-lg text-[12px] font-medium transition-colors cursor-pointer whitespace-nowrap ${deptFilter === d ? 'bg-[#1a1e2a] text-white' : 'text-gray-500 hover:bg-gray-100'}`}>{d}</button>
            ))}
          </div>
          <div className="bg-white border border-gray-100 rounded-lg overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50/70 border-b border-gray-100">
                  {['코드', '사업부', '부서명', '인원', '관리', '활성'].map((h) => (
                    <th key={h} className="text-left px-5 py-2.5 text-[11px] font-semibold text-gray-400 whitespace-nowrap">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filteredDepts.map((d) => (
                  <tr key={d.code} className="border-b border-gray-50 hover:bg-gray-50/60">
                    <td className="px-5 py-3 text-[11px] font-mono text-gray-500 whitespace-nowrap">{d.code}</td>
                    <td className="px-5 py-3 text-[12px] text-gray-600 whitespace-nowrap">{d.division}</td>
                    <td className="px-5 py-3 text-[13px] font-medium text-gray-800 whitespace-nowrap">{d.name}</td>
                    <td className="px-5 py-3 text-[12px] text-gray-600 whitespace-nowrap">{d.count}명</td>
                    <td className="px-5 py-3"><button className="text-[11px] text-teal-600 hover:text-teal-700 cursor-pointer whitespace-nowrap">수정</button></td>
                    <td className="px-5 py-3"><span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full whitespace-nowrap ${d.active ? 'bg-teal-50 text-teal-700' : 'bg-gray-100 text-gray-500'}`}>{d.active ? '활성' : '비활성'}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Perms tab */}
      {tab === 'perms' && (
        <div className="bg-white border border-gray-100 rounded-lg overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="bg-gray-50/70 border-b border-gray-100">
                {['Code', '명칭', '설명', '할당된 멤버', '관리', '활성'].map((h) => (
                  <th key={h} className="text-left px-5 py-2.5 text-[11px] font-semibold text-gray-400 whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {PERMISSIONS.map((p) => (
                <tr key={p.code} className="border-b border-gray-50 hover:bg-gray-50/60">
                  <td className="px-5 py-3 text-[11px] font-mono text-teal-600 whitespace-nowrap">{p.code}</td>
                  <td className="px-5 py-3 text-[13px] font-medium text-gray-800 whitespace-nowrap">{p.name}</td>
                  <td className="px-5 py-3 text-[12px] text-gray-600 whitespace-nowrap">{p.desc}</td>
                  <td className="px-5 py-3 text-[12px] text-gray-600 whitespace-nowrap">{p.memberCount}명</td>
                  <td className="px-5 py-3"><button className="text-[11px] text-teal-600 hover:text-teal-700 cursor-pointer whitespace-nowrap">수정</button></td>
                  <td className="px-5 py-3"><span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full whitespace-nowrap ${p.active ? 'bg-teal-50 text-teal-700' : 'bg-gray-100 text-gray-500'}`}>{p.active ? '활성' : '비활성'}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {modalMember !== undefined && (
        <UserModal member={modalMember} onClose={() => setModalMember(undefined)} onSave={handleSave} onDelete={handleDelete} />
      )}
    </div>
  );
}
