import { useState } from 'react';
import type { ActivePage } from '../types';

interface Props {
  activePage: ActivePage;
  onNavigate: (page: ActivePage) => void;
  inquiryCount?: number;
}

const navItems = [
  { id: 'dashboard' as ActivePage, icon: 'ri-dashboard-2-line', label: '대시보드' },
  { id: 'inquiry' as ActivePage, icon: 'ri-chat-3-line', label: '문의 관리', badge: true },
  { id: 'stats' as ActivePage, icon: 'ri-line-chart-line', label: '통계 분석' },
  { id: 'member' as ActivePage, icon: 'ri-user-line', label: '유저 관리' },
  { id: 'settings' as ActivePage, icon: 'ri-settings-3-line', label: '설정' },
];

const refItems = [
  { id: 'popup' as ActivePage, icon: 'ri-layout-2-line', label: '팝업·배너 관리' },
  { id: 'content' as ActivePage, icon: 'ri-file-edit-line', label: '콘텐츠 관리' },
];

export default function AdminSidebar({ activePage, onNavigate, inquiryCount = 7 }: Props) {
  const [open, setOpen] = useState(true);

  return (
    <aside
      className="bg-[#1a1e2a] text-white flex flex-col flex-shrink-0 transition-all duration-300"
      style={{ width: open ? 200 : 56, minHeight: '100vh', position: 'sticky', top: 0, height: '100vh' }}
    >
      {/* Logo */}
      <div
        className="flex items-center gap-2.5 h-[52px] px-3 border-b border-white/10 flex-shrink-0 cursor-pointer select-none"
        onClick={() => setOpen((v) => !v)}
        title={open ? '사이드바 접기' : '사이드바 열기'}
      >
        <div className="w-7 h-7 flex items-center justify-center rounded bg-teal-500 flex-shrink-0">
          <i className="ri-shield-keyhole-line text-white text-sm"></i>
        </div>
        {open && (
          <>
            <span className="text-[13px] font-bold text-white whitespace-nowrap tracking-wide">ADM Console</span>
            <button className="ml-auto w-6 h-6 flex items-center justify-center rounded hover:bg-white/10 transition-colors flex-shrink-0">
              <i className="ri-menu-fold-line text-white/40 text-sm"></i>
            </button>
          </>
        )}
      </div>

      {/* Nav */}
      <nav className="flex-1 overflow-y-auto py-3 px-2 space-y-0.5">
        {navItems.map((item) => (
          <button
            key={item.id}
            onClick={() => onNavigate(item.id)}
            title={!open ? item.label : undefined}
            className={`w-full flex items-center gap-2.5 px-2.5 py-[7px] rounded-lg text-[13px] font-medium transition-all cursor-pointer whitespace-nowrap relative ${
              activePage === item.id
                ? 'bg-teal-500 text-white'
                : 'text-white/50 hover:text-white hover:bg-white/8'
            }`}
          >
            <div className="w-5 h-5 flex items-center justify-center flex-shrink-0">
              <i className={`${item.icon} text-[15px]`}></i>
            </div>
            {open && <span>{item.label}</span>}
            {open && item.badge && inquiryCount > 0 && (
              <span className="ml-auto bg-rose-500 text-white text-[10px] font-bold rounded-full min-w-[18px] h-[18px] flex items-center justify-center px-1">
                {inquiryCount}
              </span>
            )}
            {!open && item.badge && inquiryCount > 0 && (
              <span className="absolute top-0.5 right-0.5 w-2 h-2 rounded-full bg-rose-500"></span>
            )}
          </button>
        ))}

        <div className="pt-3 pb-1">
          <div className={`px-2.5 text-[10px] font-semibold text-white/25 uppercase tracking-widest ${!open ? 'hidden' : ''}`}>
            참고 메뉴
          </div>
          {!open && <div className="border-t border-white/10 my-1" />}
        </div>

        {refItems.map((item) => (
          <button
            key={item.id}
            onClick={() => onNavigate(item.id)}
            title={!open ? item.label : undefined}
            className={`w-full flex items-center gap-2.5 px-2.5 py-[7px] rounded-lg text-[13px] font-medium transition-all cursor-pointer whitespace-nowrap ${
              activePage === item.id
                ? 'bg-teal-500 text-white'
                : 'text-white/50 hover:text-white hover:bg-white/8'
            }`}
          >
            <div className="w-5 h-5 flex items-center justify-center flex-shrink-0">
              <i className={`${item.icon} text-[15px]`}></i>
            </div>
            {open && <span>{item.label}</span>}
          </button>
        ))}
      </nav>

      {/* Footer user */}
      <div className="px-2 pb-3 pt-2 border-t border-white/10 flex-shrink-0">
        <div className={`flex items-center gap-2.5 px-2.5 py-2 rounded-lg text-[12px] text-white/50 ${open ? '' : 'justify-center'}`}>
          <div className="w-6 h-6 rounded-full bg-teal-500 flex items-center justify-center flex-shrink-0">
            <span className="text-white text-[10px] font-bold">김</span>
          </div>
          {open && (
            <div className="leading-tight">
              <div className="text-white/80 font-medium text-[12px]">김광연</div>
              <div className="text-white/30 text-[10px]">100001 · 시스템 관리자</div>
            </div>
          )}
        </div>
      </div>
    </aside>
  );
}
