import { useState, useEffect } from 'react';

export default function ScrollNavButtons() {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const onScroll = () => {
      setVisible(window.scrollY > 300);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const scrollToTop = () => window.scrollTo({ top: 0, behavior: 'smooth' });

  return (
    <button
      onClick={scrollToTop}
      title="맨 위로"
      className="fixed bottom-8 right-6 z-50 w-11 h-11 flex items-center justify-center rounded-full border-2 border-green-500 text-green-500 bg-white hover:bg-green-50 transition-all duration-300 cursor-pointer"
      style={{
        opacity: visible ? 1 : 0,
        pointerEvents: visible ? 'auto' : 'none',
        transform: visible ? 'translateY(0)' : 'translateY(16px)',
      }}
    >
      <svg width="18" height="14" viewBox="0 0 18 14" fill="none">
        <path d="M2 12L9 3L16 12" stroke="#22c55e" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    </button>
  );
}
