import { useState } from 'react';

export default function Contact() {
  const [formData, setFormData] = useState({
    name: '',
    company: '',
    email: '',
    phone: '',
    services: [] as string[],
    message: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const serviceOptions = ['AppSuit 제품', '모의해킹', '보안 컨설팅', 'R&D 서비스'];

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleCheck = (val: string) => {
    setFormData((prev) => ({
      ...prev,
      services: prev.services.includes(val)
        ? prev.services.filter((s) => s !== val)
        : [...prev.services, val],
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.message.length > 500) return;
    setIsSubmitting(true);
    setSubmitStatus('idle');
    try {
      const body = new URLSearchParams();
      body.append('name', formData.name);
      body.append('company', formData.company);
      body.append('email', formData.email);
      body.append('phone', formData.phone);
      body.append('service', formData.services.join(', '));
      body.append('message', formData.message);
      const res = await fetch('https://readdy.ai/api/form/d6s0noba90d3mf3eh5s0', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: body.toString(),
      });
      if (res.ok) {
        setSubmitStatus('success');
        setFormData({ name: '', company: '', email: '', phone: '', services: [], message: '' });
      } else {
        setSubmitStatus('error');
      }
    } catch {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <section id="contact" className="py-7 bg-gray-50">
      <div className="max-w-content mx-auto px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-12 items-start">
          {/* Left — Form */}
          <div>
  
            <h2 className="text-3xl font-black text-gray-900 mb-2">무료 상담 신청</h2>
            <p className="text-sm text-gray-500 mb-6 leading-relaxed">
              보안 전문가가 귀사의 상황에 맞는 최적의 솔루션을 제안해드립니다.<br />
              <strong className="text-gray-700">영업일 기준 24시간 이내 담당자 직접 연락.</strong>
            </p>

            <form id="consulting-form-main" onSubmit={handleSubmit} data-readdy-form className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-semibold text-gray-700 mb-1.5">이름 <span className="text-red-500">*</span></label>
                  <input
                    type="text" name="name" value={formData.name} onChange={handleChange} required
                    placeholder="홍길동"
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-400 focus:border-transparent outline-none"
                  />
                </div>
                <div>
                  <label className="block text-xs font-semibold text-gray-700 mb-1.5">회사명 <span className="text-red-500">*</span></label>
                  <input
                    type="text" name="company" value={formData.company} onChange={handleChange} required
                    placeholder="(주)스틸리언"
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-400 focus:border-transparent outline-none"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-semibold text-gray-700 mb-1.5">이메일 <span className="text-red-500">*</span></label>
                  <input
                    type="email" name="email" value={formData.email} onChange={handleChange} required
                    placeholder="example@company.com"
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-400 focus:border-transparent outline-none"
                  />
                </div>
                <div>
                  <label className="block text-xs font-semibold text-gray-700 mb-1.5">연락처 <span className="text-red-500">*</span></label>
                  <input
                    type="tel" name="phone" value={formData.phone} onChange={handleChange} required
                    placeholder="010-1234-5678"
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-400 focus:border-transparent outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-semibold text-gray-700 mb-2">관심 서비스 <span className="text-red-500">*</span></label>
                <div className="flex flex-wrap gap-2">
                  {serviceOptions.map((s) => (
                    <label
                      key={s}
                      className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-xs font-medium cursor-pointer transition-colors ${
                        formData.services.includes(s)
                          ? 'bg-teal-50 border-teal-400 text-teal-700'
                          : 'bg-white border-gray-200 text-gray-600 hover:border-teal-300'
                      }`}
                    >
                      <input
                        type="checkbox"
                        className="hidden"
                        checked={formData.services.includes(s)}
                        onChange={() => handleCheck(s)}
                      />
                      {formData.services.includes(s) && <i className="ri-check-line text-teal-600 text-sm"></i>}
                      {s}
                    </label>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-semibold text-gray-700 mb-1.5">문의 내용</label>
                <textarea
                  name="message" value={formData.message} onChange={handleChange}
                  maxLength={500} rows={4}
                  placeholder="문의하실 내용을 입력해 주세요. (최대 500자)"
                  className="w-full px-3 py-2.5 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-400 focus:border-transparent outline-none resize-none"
                />
                <div className="text-right text-xs text-gray-400 -mt-1">{formData.message.length}/500</div>
              </div>

              <button
                type="submit" disabled={isSubmitting}
                className="w-full bg-teal-600 text-white py-3.5 rounded-xl text-sm font-bold hover:bg-teal-700 transition-colors disabled:bg-gray-300 whitespace-nowrap cursor-pointer"
              >
                {isSubmitting ? '전송 중...' : '상담 신청하기'}
              </button>

              {submitStatus === 'success' && (
                <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg text-sm">
                  문의가 성공적으로 접수되었습니다. 빠른 시일 내에 연락드리겠습니다.
                </div>
              )}
              {submitStatus === 'error' && (
                <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg text-sm">
                  문의 접수 중 오류가 발생했습니다. 다시 시도해주세요.
                </div>
              )}

              <p className="text-xs text-gray-400">
                개인정보 수집·이용에 동의합니다.{' '}
                <a href="#" className="underline hover:text-teal-600">개인정보처리방침</a>
              </p>
            </form>
          </div>

          {/* Right — Contact info */}
          <div className="space-y-6 lg:pt-14">
            <div className="bg-white border border-gray-100 rounded-2xl p-6 space-y-5">
              {[
                { icon: 'ri-phone-line', label: '영업 문의', tel: '02-2088-4834', email: 'sales@stealien.com' },
                { icon: 'ri-headphone-line', label: '기술 지원', tel: '02-2088-4835', email: 'se@stealien.com' },
                { icon: 'ri-mail-line', label: '대표 문의', tel: '02-2038-4792', email: 'contact@stealien.com' },
              ].map((item) => (
                <div key={item.label} className="flex items-start gap-4">
                  <div className="w-10 h-10 flex items-center justify-center bg-teal-50 border border-teal-100 rounded-xl flex-shrink-0">
                    <i className={`${item.icon} text-teal-600 text-lg`}></i>
                  </div>
                  <div>
                    <div className="text-xs font-bold text-gray-500 mb-0.5">{item.label}</div>
                    <div className="text-base font-black text-gray-900">{item.tel}</div>
                    <div className="text-xs text-gray-500">{item.email}</div>
                  </div>
                </div>
              ))}
            </div>

            <div className="bg-white border border-gray-100 rounded-2xl p-6">
              <div className="text-sm font-black text-gray-900 mb-3">빠른 응답 보장</div>
              <ul className="space-y-2.5">
                {[
                  '영업일 기준 24시간 이내 1차 응답',
                  '전담 컨설턴트 배정',
                  '맞춤형 솔루션 제안',
                  '무료 데모 및 PoC 지원',
                ].map((txt) => (
                  <li key={txt} className="flex items-center gap-2 text-sm text-gray-700">
                    <i className="ri-check-line text-teal-500 flex-shrink-0"></i>
                    {txt}
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
