function BigChart({ data, period }: { data: { label: string; val: number }[]; period: Period }) {
  const W = 580; const H = 200; const PL = 56; const PR = 10; const PT = 16; const PB = 28;
  const cW = W - PL - PR; const cH = H - PT - PB;
  const maxV = Math.max(...data.map((d) => d.val));

  // 일 단위는 더 세밀한 눈금, 나머지는 일반 스케일
  const niceStepCount = period === '일' ? 5 : 4;
  const rawStep = maxV / niceStepCount;
  const magnitude = Math.pow(10, Math.floor(Math.log10(rawStep)));
  const niceStep = Math.ceil(rawStep / magnitude) * magnitude;
  const niceMax = niceStep * niceStepCount;
  const yTicks = Array.from({ length: niceStepCount + 1 }, (_, i) => Math.round(niceStep * i));

  const toX = (i: number) => PL + (i / Math.max(data.length - 1, 1)) * cW;
  const toY = (v: number) => PT + cH - (v / niceMax) * cH;
  const pathD = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${toX(i).toFixed(1)} ${toY(d.val).toFixed(1)}`).join(' ');
  const areaD = pathD + ` L ${toX(data.length - 1).toFixed(1)} ${(PT + cH).toFixed(1)} L ${toX(0).toFixed(1)} ${(PT + cH).toFixed(1)} Z`;
  const [hov, setHov] = useState<number | null>(null);

  const fmt = (v: number) => {
    if (period === '일') return v >= 1000 ? `${(v / 1000).toFixed(1)}k` : v.toLocaleString();
    return v >= 10000 ? `${(v / 1000).toFixed(0)}k` : v.toLocaleString();
  };

  return (
    <div className="relative w-full" style={{ paddingBottom: '34%' }}>
      <svg viewBox={`0 0 ${W} ${H}`} className="absolute inset-0 w-full h-full" onMouseLeave={() => setHov(null)}>
        <defs>
          <linearGradient id="sg" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#14b8a6" stopOpacity="0.14" />
            <stop offset="100%" stopColor="#14b8a6" stopOpacity="0" />
          </linearGradient>
        </defs>
        {yTicks.map((t) => (
          <g key={t}>
            <line x1={PL} y1={toY(t)} x2={W - PR} y2={toY(t)} stroke="#f0f4f8" strokeWidth="1" />
            <text x={PL - 4} y={toY(t) + 4} textAnchor="end" fontSize="9" fill="#b0bec5">{fmt(t)}</text>
          </g>
        ))}
        {data.map((d, i) => <text key={`x${i}`} x={toX(i)} y={H - 6} textAnchor="middle" fontSize="9" fill="#b0bec5">{d.label}</text>)}
        <path d={areaD} fill="url(#sg)" />
        <path d={pathD} fill="none" stroke="#14b8a6" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
        {data.map((d, i) => (
          <g key={`sp${i}`}>
            <circle cx={toX(i)} cy={toY(d.val)} r={hov === i ? 5 : 3} fill={hov === i ? '#14b8a6' : '#fff'} stroke="#14b8a6" strokeWidth="2" />
            <rect x={toX(i) - 18} y={PT} width={36} height={cH} fill="transparent" onMouseEnter={() => setHov(i)} />
            {hov === i && (
              <g>
                <rect x={toX(i) - 28} y={toY(d.val) - 24} width={56} height={18} rx={3} fill="#0f766e" />
                <text x={toX(i)} y={toY(d.val) - 11} textAnchor="middle" fontSize="10" fill="#fff" fontWeight="600">{fmt(d.val)}</text>
              </g>
            )}
          </g>
        ))}
      </svg>
    </div>
  );
}

