function ThreatDonut() {
  const [active, setActive] = useState<number | null>(null);
  const total = 167;
  const radius = 70;
  const cx = 90;
  const cy = 90;
  const strokeWidth = 22;
  const circumference = 2 * Math.PI * radius;

  let offset = 0;
  const segments = threatData.map((d, i) => {
    const dash = (d.percent / 100) * circumference;
    const gap = circumference - dash;
    const startOffset = offset;
    offset += dash;
    return { ...d, dash, gap, startOffset, idx: i };
  });

  const colors = ['#14b8a6', '#0d9488', '#5eead4', '#ccfbf1'];

  return (
    <div className="flex items-center gap-8">
      <div className="relative shrink-0" style={{ width: 180, height: 180 }}>
        <svg width="180" height="180" className="rotate-[-90deg]">
          {segments.map((seg) => (
            <circle
              key={seg.idx}
              cx={cx}
              cy={cy}
              r={radius}
              fill="none"
              stroke={colors[seg.idx]}
              strokeWidth={strokeWidth}
              strokeDasharray={`${seg.dash} ${circumference - seg.dash}`}
              strokeDashoffset={-seg.startOffset}
              className="cursor-pointer transition-all"
              opacity={active === null || active === seg.idx ? 1 : 0.35}
              onMouseEnter={() => setActive(seg.idx)}
              onMouseLeave={() => setActive(null)}
            />
          ))}
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <p className="text-2xl font-bold text-gray-900">{active !== null ? threatData[active].count : total}</p>
          <p className="text-xs text-gray-400">{active !== null ? threatData[active].label : '전체 탐지'}</p>
        </div>
      </div>
      <div className="space-y-3 flex-1">
        {threatData.map((d, i) => (
          <div
            key={i}
            className="cursor-pointer group"
            onMouseEnter={() => setActive(i)}
            onMouseLeave={() => setActive(null)}
          >
            <div className="flex justify-between text-xs mb-1">
              <span className={`font-semibold ${active === i ? 'text-teal-600' : 'text-gray-700'} transition-colors`}>{d.label}</span>
              <span className="text-gray-500">{d.count}건 ({d.percent}%)</span>
            </div>
            <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
              <div
                className={`h-full rounded-full transition-all ${d.bgClass}`}
                style={{ width: `${d.percent * 1.85}%`, opacity: active === null || active === i ? 1 : 0.35 }}
              ></div>
            </div>
          </div>
        ))}
        <p className="text-[10px] text-gray-400 pt-1">* 실제 고객사 탐지 데이터 기반 예시</p>
      </div>
    </div>
  );
}

