const languages = [
  { code: 'ko', label: 'KR' },
  { code: 'en', label: 'EN' },
  { code: 'ja', label: 'JP' },
  { code: 'id', label: 'ID' },
];

export default function Navbar() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isVisible, setIsVisible] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);
  const [selectedLang, setSelectedLang] = useState('ko');
  const [mobileExpanded, setMobileExpanded] = useState<string | null>(null);
  const closeTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const lastScrollY = useRef(0);
  const location = useLocation();

  const isHomePage = location.pathname === '/';
  const navigate = useNavigate();
  const { openPopup } = useContactPopup();

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;
      if (currentScrollY < 10) {
        setIsVisible(true);
        setIsScrolled(false);
        lastScrollY.current = currentScrollY;
        return;
      }
      setIsScrolled(currentScrollY > 50);
      if (currentScrollY > lastScrollY.current + 5) {
        setIsVisible(false);
        setActiveDropdown(null);
      } else if (currentScrollY < lastScrollY.current - 5) {
        setIsVisible(true);
      }
      lastScrollY.current = currentScrollY;
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleMouseEnter = (label: string) => {
    if (closeTimer.current) {
      clearTimeout(closeTimer.current);
      closeTimer.current = null;
    }
    setActiveDropdown(label);
  };

  const handleMouseLeave = () => {
    closeTimer.current = setTimeout(() => {
      setActiveDropdown(null);
    }, 150);
  };

  const showScrolled = isScrolled || !isHomePage;
  const textColor = showScrolled ? 'text-gray-700' : 'text-white';
  const hoverColor = showScrolled ? 'hover:text-teal-600' : 'hover:text-teal-300';

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        showScrolled ? 'bg-white border-b border-gray-100' : 'bg-transparent'
      } ${isVisible ? 'translate-y-0' : '-translate-y-full'}`}
    >
      <div className="max-w-content mx-auto px-6 lg:px-8">
        <div className="flex items-center h-16 gap-8">
          {/* Logo */}
          <Link to="/" className="flex items-center flex-shrink-0">
            <div className="relative h-8" style={{ width: 'auto', minWidth: '120px' }}>
              <img
                src="https://static.readdy.ai/image/39c5707ce5cd6f50fdeaed77f9779858/df05f34631cb15e2c84bf06928db96d5.jpeg"
                alt="스틸리언 로고"
                className="h-8 w-auto transition-opacity duration-300"
                style={{ opacity: showScrolled ? 1 : 0 }}
              />
              <img
                src="https://storage.readdy-site.link/project_files/933ce64b-27f5-4a0a-a32e-588024784346/c5a81740-861a-4eb1-98de-65ed7bd3f5ac_-..png?v=ab1af4cb06a9f5a8d54090e538293140"
                alt="스틸리언 로고 (흰색)"
                className="absolute top-0 left-0 h-8 w-auto transition-opacity duration-300"
                style={{ opacity: showScrolled ? 0 : 1 }}
              />
            </div>
          </Link>

          {/* Desktop Center Nav */}
          <div className="hidden lg:flex items-center flex-1 justify-center gap-0.5">
            {navItems.map((nav) => {
              if (nav.href && !nav.megaMenu) {
                return (
                  <Link
                    key={nav.label}
                    to={nav.href}
                    className={`flex items-center px-3.5 py-2 text-sm font-medium transition-colors whitespace-nowrap cursor-pointer rounded-md ${textColor} ${hoverColor}`}
                  >
                    {nav.label}
                  </Link>
                );
              }

              const isActive = activeDropdown === nav.label;

              return (
                <div
                  key={nav.label}
                  className="relative"
                  onMouseEnter={() => handleMouseEnter(nav.label)}
                  onMouseLeave={handleMouseLeave}
                >
                  <button
                    onClick={() => setActiveDropdown(isActive ? null : nav.label)}
                    className={`flex items-center gap-1 px-3.5 py-2 text-sm font-medium transition-colors whitespace-nowrap cursor-pointer rounded-md ${textColor} ${hoverColor}`}
                  >
                    {nav.label}
                    <i className={`ri-arrow-down-s-line text-xs transition-transform duration-200 ${isActive ? 'rotate-180' : ''}`}></i>
                  </button>

                  {isActive && nav.megaMenu && (
                    <div
                      className="absolute top-full left-1/2 -translate-x-1/2 bg-white rounded-2xl border border-gray-100 z-50 mt-2 overflow-hidden"
                      style={{ minWidth: '680px', boxShadow: '0 8px 40px rgba(0,0,0,0.10)' }}
                      onMouseEnter={() => handleMouseEnter(nav.label)}
                      onMouseLeave={handleMouseLeave}
                    >
                      <div className="absolute -top-3 left-0 right-0 h-3 bg-transparent"></div>
                      {nav.megaMenu.map((section) => (
                        <div key={section.sectionTitle} className="flex">
                          {/* Left: Section description */}
                          <div className="w-52 flex-shrink-0 bg-gray-50 p-6 flex flex-col justify-between">
                            <div>
                              <div className="w-10 h-10 flex items-center justify-center rounded-xl bg-teal-50 mb-4">
                                <i className={`${section.sectionIcon} text-teal-600 text-xl`}></i>
                              </div>
                              <p className="text-xs font-semibold text-teal-600 uppercase tracking-widest mb-2">
                                {section.sectionTitle}
                              </p>
                              <p className="text-sm font-semibold text-gray-800 leading-snug whitespace-pre-line">
                                {section.sectionDesc}
                              </p>
                            </div>
                            {section.sectionHref && (
                              <Link
                                to={section.sectionHref}
                                className="mt-4 flex items-center gap-1 text-xs font-semibold text-teal-600 hover:text-teal-700 transition-colors group"
                                onClick={() => setActiveDropdown(null)}
                              >
                                전체 보기
                                <i className="ri-arrow-right-line text-xs transition-transform group-hover:translate-x-0.5"></i>
                              </Link>
                            )}
                          </div>

                          {/* Right: Menu items grid */}
                          <div className="flex-1 p-4">
                            <div
                              className={`grid gap-1 ${
                                section.items.length <= 3
                                  ? 'grid-cols-1'
                                  : section.items.length <= 6
                                  ? 'grid-cols-2'
                                  : 'grid-cols-2'
                              }`}
                            >
                              {section.items.map((item) =>
                                item.soon ? (
                                  <div
                                    key={item.label}
                                    className="flex items-start gap-3 px-4 py-3 rounded-xl cursor-default select-none opacity-50"
                                  >
                                    <div className="w-8 h-8 flex items-center justify-center flex-shrink-0 rounded-lg bg-gray-100">
                                      <i className={`${item.icon} text-gray-400 text-sm`}></i>
                                    </div>
                                    <div className="min-w-0">
                                      <div className="flex items-center gap-2 mb-0.5">
                                        <span className="text-sm font-medium text-gray-400">{item.label}</span>
                                        {item.tag && (
                                          <span className="text-[10px] font-semibold px-1.5 py-0.5 rounded-full bg-gray-100 text-gray-400">
                                            {item.tag}
                                          </span>
                                        )}
                                      </div>
                                      <p className="text-xs text-gray-400 leading-snug">{item.desc}</p>
                                    </div>
                                  </div>
                                ) : (
                                  <Link
                                    key={item.href}
                                    to={item.href}
                                    className="flex items-start gap-3 px-4 py-3 rounded-xl hover:bg-teal-50 transition-colors cursor-pointer group"
                                    onClick={() => setActiveDropdown(null)}
                                  >
                                    <div className="w-8 h-8 flex items-center justify-center flex-shrink-0 rounded-lg bg-gray-100 group-hover:bg-teal-100 transition-colors">
                                      <i className={`${item.icon} text-gray-500 group-hover:text-teal-600 text-sm transition-colors`}></i>
                                    </div>
                                    <div className="min-w-0">
                                      <div className="flex items-center gap-2 mb-0.5">
                                        <span className="text-sm font-medium text-gray-800 group-hover:text-teal-700 transition-colors whitespace-nowrap">
                                          {item.label}
                                        </span>
                                        {item.labelSub && (
                                          <span className="text-xs text-gray-400 whitespace-nowrap">({item.labelSub})</span>
                                        )}
                                        {item.tag && (
                                          <span className="text-[10px] font-semibold px-1.5 py-0.5 rounded-full bg-teal-50 text-teal-600 whitespace-nowrap">
                                            {item.tag}
                                          </span>
                                        )}
                                      </div>
                                      <p className="text-xs text-gray-500 leading-snug">{item.desc}</p>
                                    </div>
                                  </Link>
                                )
                              )}
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Desktop Right Side */}
          <div className="hidden lg:flex items-center gap-3 flex-shrink-0">
            <button
              type="button"
              onClick={() => openPopup('document')}
              className={`flex items-center gap-1.5 px-4 py-2 text-sm font-medium border rounded-md transition-colors whitespace-nowrap cursor-pointer ${
                showScrolled
                  ? 'border-gray-200 text-gray-600 hover:border-teal-400 hover:text-teal-600'
                  : 'border-white/30 text-white/80 hover:border-white hover:text-white'
              }`}
            >
              <i className="ri-file-download-line text-sm"></i>
              자료 요청
            </button>
            <button
              type="button"
              onClick={() => openPopup('inquiry')}
              className="flex items-center gap-1.5 px-4 py-2 text-sm font-semibold rounded-md bg-teal-500 text-white hover:bg-teal-600 transition-colors whitespace-nowrap cursor-pointer"
            >
              <i className="ri-chat-check-line text-sm"></i>
              도입 상담
            </button>

            {/* Language */}
            <div className="flex items-center gap-0 ml-1">
              {languages.map((lang, idx) => (
                <div key={lang.code} className="flex items-center">
                  {idx > 0 && (
                    idx === 3 ? (
                      <span
                        className={`text-xs select-none cursor-pointer px-0.5 ${showScrolled ? 'text-gray-300' : 'text-white/40'}`}
                        onClick={() => navigate('/admin-console')}
                      >|</span>
                    ) : (
                      <span className={`text-xs select-none px-0.5 ${showScrolled ? 'text-gray-300' : 'text-white/40'}`}>|</span>
                    )
                  )}
                  <button
                    className={`px-1.5 py-1 text-xs font-semibold transition-colors whitespace-nowrap cursor-pointer ${
                      selectedLang === lang.code
                        ? showScrolled ? 'text-teal-600' : 'text-white font-bold'
                        : showScrolled ? 'text-gray-400 hover:text-gray-700' : 'text-white/60 hover:text-white'
                    }`}
                    onClick={() => setSelectedLang(lang.code)}
                  >
                    {lang.label}
                  </button>
                </div>
              ))}
            </div>
          </div>

          {/* Mobile Menu Button */}
          <button
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            className="lg:hidden p-2 cursor-pointer ml-auto"
          >
            <div className="w-6 h-5 flex flex-col justify-between">
              <span className={`block h-0.5 w-full transition-all ${showScrolled ? 'bg-gray-800' : 'bg-white'}`}></span>
              <span className={`block h-0.5 w-full transition-all ${showScrolled ? 'bg-gray-800' : 'bg-white'}`}></span>
              <span className={`block h-0.5 w-full transition-all ${showScrolled ? 'bg-gray-800' : 'bg-white'}`}></span>
            </div>
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="lg:hidden bg-white border-t border-gray-200 max-h-[80vh] overflow-y-auto">
          <div className="px-4 py-3 space-y-1">
            {navItems.map((nav) => {
              if (nav.href && !nav.megaMenu) {
                return (
                  <Link
                    key={nav.label}
                    to={nav.href}
                    className="block px-3 py-3 text-sm font-semibold text-gray-800 hover:text-teal-600 cursor-pointer"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    {nav.label}
                  </Link>
                );
              }

              const allItems = (nav.megaMenu ?? []).flatMap((s) => s.items);

              return (
                <div key={nav.label}>
                  <button
                    className="w-full flex items-center justify-between px-3 py-3 text-sm font-semibold text-gray-800 hover:text-teal-600 cursor-pointer"
                    onClick={() => setMobileExpanded(mobileExpanded === nav.label ? null : nav.label)}
                  >
                    <span>{nav.label}</span>
                    <i className={`ri-arrow-down-s-line transition-transform ${mobileExpanded === nav.label ? 'rotate-180' : ''}`}></i>
                  </button>
                  {mobileExpanded === nav.label && (
                    <div className="pl-4 pb-2 space-y-0.5">
                      {allItems.map((item) =>
                        item.soon ? (
                          <div
                            key={item.label}
                            className="flex items-center gap-2 px-3 py-2.5 text-sm text-gray-400 cursor-default select-none"
                          >
                            <i className={`${item.icon} text-gray-300`}></i>
                            <span>{item.label}</span>
                            <span className="text-xs bg-gray-100 text-gray-400 px-1.5 py-0.5 rounded-full">예정</span>
                          </div>
                        ) : (
                          <Link
                            key={item.href}
                            to={item.href}
                            className="flex items-center gap-2.5 px-3 py-2.5 text-sm text-gray-700 hover:text-teal-600 hover:bg-teal-50 rounded-lg cursor-pointer transition-colors"
                            onClick={() => setIsMobileMenuOpen(false)}
                          >
                            <i className={`${item.icon} text-gray-400 text-base`}></i>
                            <span>{item.label}</span>
                            {item.labelSub && (
                              <span className="text-xs text-gray-400">({item.labelSub})</span>
                            )}
                          </Link>
                        )
                      )}
                    </div>
                  )}
                </div>
              );
            })}

            {/* Mobile CTA */}
            <div className="pt-2 border-t border-gray-100 flex gap-2">
              <button
                type="button"
                className="flex-1 text-center px-4 py-2.5 text-sm font-medium border border-gray-200 rounded-md text-gray-700 hover:border-teal-400 hover:text-teal-600 cursor-pointer whitespace-nowrap"
                onClick={() => { setIsMobileMenuOpen(false); openPopup('document'); }}
              >
                자료 요청
              </button>
              <button
                type="button"
                className="flex-1 text-center px-4 py-2.5 text-sm font-semibold bg-teal-500 text-white rounded-md hover:bg-teal-600 cursor-pointer whitespace-nowrap"
                onClick={() => { setIsMobileMenuOpen(false); openPopup('inquiry'); }}
              >
                도입 상담
              </button>
            </div>

            {/* Language */}
            <div className="pt-2 border-t border-gray-100">
              <p className="px-3 py-2 text-xs font-semibold text-gray-400 uppercase tracking-wider">언어 선택</p>
              <div className="flex items-center gap-0 px-3 pb-2">
                {languages.map((lang, idx) => (
                  <div key={lang.code} className="flex items-center">
                    {idx > 0 && (
                      <span className="text-xs text-gray-300 select-none px-0.5">|</span>
                    )}
                    <button
                      className={`px-2.5 py-1.5 text-sm font-semibold cursor-pointer transition-colors ${
                        selectedLang === lang.code ? 'text-teal-600' : 'text-gray-400 hover:text-gray-700'
                      }`}
                      onClick={() => setSelectedLang(lang.code)}
                    >
                      {lang.label}
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
}
