import { Link, useLocation } from 'react-router-dom';

const companyMenus = [
  { label: '회사소개', href: '/company/about', icon: 'ri-building-line' },
  { label: '연혁', href: '/company/history', icon: 'ri-history-line' },
  { label: '언론보도', href: '/company/press', icon: 'ri-newspaper-line' },
  { label: 'CI', href: '/support/ci', icon: 'ri-palette-line' },
  { label: '수상 및 인증', href: '/company/awards', icon: 'ri-award-line' },
  { label: '멘토링 프로그램', href: '/company/mentoring', icon: 'ri-graduation-cap-line' },
  { label: '채용', href: '/company/recruit', icon: 'ri-user-add-line' },
  { label: '오시는 길', href: '/company/contact', icon: 'ri-map-pin-line' },
];

export default function CompanySubNav() {
  const location = useLocation();

  return (
    <div className="bg-white border-b border-gray-200 sticky top-14 z-40 shadow-sm">
      <div className="max-w-content mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center overflow-x-auto scrollbar-hide gap-1 py-0">
          {companyMenus.map((menu) => {
            const isActive = location.pathname === menu.href;
            return (
              <Link
                key={menu.href}
                to={menu.href}
                className={`flex items-center gap-1.5 px-4 py-3.5 text-sm font-medium whitespace-nowrap transition-all border-b-2 cursor-pointer ${
                  isActive
                    ? 'border-teal-600 text-teal-600'
                    : 'border-transparent text-gray-500 hover:text-gray-800 hover:border-gray-300'
                }`}
              >
                <i className={`${menu.icon} text-base`}></i>
                {menu.label}
              </Link>
            );
          })}
        </div>
      </div>
    </div>
  );
}
