export default function Cases() {
  const [activeTab, setActiveTab] = useState('finance');
  const kpiRefs = useRef<(HTMLDivElement | null)[]>([]);
  const reviewRefs = useRef<(HTMLDivElement | null)[]>([]);

  const activeIndustry = industries.find((ind) => ind.id === activeTab) ?? industries[0];

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('opacity-100', 'translate-y-0');
            entry.target.classList.remove('opacity-0', 'translate-y-5');
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.05, rootMargin: '0px 0px -20px 0px' }
    );
    [...kpiRefs.current, ...reviewRefs.current].forEach((el) => {
      if (!el) return;
      const rect = el.getBoundingClientRect();
      if (rect.top < window.innerHeight && rect.bottom > 0) {
        el.classList.add('opacity-100', 'translate-y-0');
        el.classList.remove('opacity-0', 'translate-y-5');
      } else {
        observer.observe(el);
      }
    });
    return () => observer.disconnect();
  }, []);

  return (
    <section id="cases" className="py-7 bg-gray-50">
      <div className="max-w-content mx-auto px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-8">
          <h2 className="text-3xl md:text-4xl font-black text-gray-900 mb-4">
            모바일 앱과 정보 자산을 지켜 드립니다
          </h2>
        </div>

        {/* KPI Row */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-5 mb-12">
          {kpis.map((k, i) => (
            <div
              key={i}
              ref={(el) => { kpiRefs.current[i] = el; }}
              className="opacity-0 translate-y-5 transition-all duration-600 bg-white border border-gray-100 rounded-2xl p-6 text-center hover:border-teal-200 hover:shadow-md"
              style={{ transitionDelay: `${i * 80}ms` }}
            >
              <div className="text-3xl font-black text-gray-900 mb-1">
                {k.num}<span className="text-teal-600">{k.suffix}</span>
              </div>
              <div className="text-sm text-gray-500">{k.label}</div>
            </div>
          ))}
        </div>

        {/* Industry Tabs */}
        <div className="bg-white border border-gray-100 rounded-2xl overflow-hidden mb-8">
          {/* Tab bar */}
          <div className="flex overflow-x-auto border-b border-gray-100">
            {industries.map((ind) => (
              <button
                key={ind.id}
                onClick={() => setActiveTab(ind.id)}
                className={`flex-shrink-0 px-5 py-3.5 text-sm font-semibold transition-colors whitespace-nowrap cursor-pointer ${
                  activeTab === ind.id
                    ? 'text-teal-600 border-b-2 border-teal-600 bg-teal-50/50'
                    : 'text-gray-500 hover:text-gray-800 hover:bg-gray-50'
                }`}
              >
                {ind.label}
              </button>
            ))}
          </div>
          {/* Panel */}
          <div className="p-8 flex gap-6 items-start">
            <div className="text-5xl flex-shrink-0">{activeIndustry.icon}</div>
            <div className="flex-1 min-w-0">
              <div className="text-lg font-black text-gray-900 mb-1">{activeIndustry.title}</div>
              <div className="text-sm text-gray-500 mb-3">{activeIndustry.clients}</div>
              <p className="text-sm text-gray-700 leading-relaxed mb-3">{activeIndustry.desc}</p>
              <div className="text-xs text-gray-400 bg-gray-50 border border-gray-100 rounded-lg px-3 py-2 inline-block">
                {activeIndustry.ref}
              </div>
            </div>
          </div>
        </div>

        {/* Reviews */}
        <div className="grid md:grid-cols-3 gap-5">
          {reviews.map((r, i) => (
            <div
              key={i}
              ref={(el) => { reviewRefs.current[i] = el; }}
              className="opacity-0 translate-y-5 transition-all duration-600 bg-white border border-gray-100 rounded-2xl p-6 hover:border-teal-200 hover:shadow-md"
              style={{ transitionDelay: `${i * 100}ms` }}
            >
              <div className="flex mb-3">
                {Array.from({ length: r.stars }).map((_, si) => (
                  <i key={si} className="ri-star-fill text-yellow-400 text-base"></i>
                ))}
              </div>
              <p className="text-sm text-gray-700 leading-relaxed mb-4 italic">{r.text}</p>
              <div className="border-t border-gray-100 pt-3">
                <div className="text-sm font-bold text-gray-900">{r.company}</div>
                <div className="text-xs text-gray-500">{r.role}</div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
