import { createContext, useContext, useState, ReactNode } from 'react';

export type ContactPopupType = 'inquiry' | 'document';

interface ContactPopupContextValue {
  isOpen: boolean;
  popupType: ContactPopupType;
  openPopup: (type?: ContactPopupType) => void;
  closePopup: () => void;
}

const ContactPopupContext = createContext<ContactPopupContextValue | null>(null);

export function ContactPopupProvider({ children }: { children: ReactNode }) {
  const [isOpen, setIsOpen] = useState(false);
  const [popupType, setPopupType] = useState<ContactPopupType>('inquiry');

  const openPopup = (type: ContactPopupType = 'inquiry') => {
    setPopupType(type);
    setIsOpen(true);
  };

  const closePopup = () => setIsOpen(false);

  return (
    <ContactPopupContext.Provider value={{ isOpen, popupType, openPopup, closePopup }}>
      {children}
    </ContactPopupContext.Provider>
  );
}

export function useContactPopup() {
  const ctx = useContext(ContactPopupContext);
  if (!ctx) throw new Error('useContactPopup must be used within ContactPopupProvider');
  return ctx;
}
