import { useState, useMemo } from 'react';
import { INQUIRIES, MEMBERS } from '../mockData';
import type { Inquiry, InquiryStatus } from '../types';

const STATUS_STYLE: Record<InquiryStatus, string> = {
  신규: 'bg-sky-50 text-sky-700',
  처리중: 'bg-amber-50 text-amber-700',
  완료: 'bg-teal-50 text-teal-700',
  보류: 'bg-gray-100 text-gray-500',
};
const TYPE_STYLE: Record<string, string> = {
  '제품': 'bg-teal-50 text-teal-700',
  '컨설팅': 'bg-sky-50 text-sky-700',
  'R&D': 'bg-rose-50 text-rose-700',
  '기타': 'bg-gray-100 text-gray-600',
};

const PAGE_SIZE = 10;

interface ModalProps {
  inquiry: Inquiry;
  onClose: () => void;
  onSave: (updated: Inquiry) => void;
}

function InquiryModal({ inquiry, onClose, onSave }: ModalProps) {
  const [status, setStatus] = useState<InquiryStatus>(inquiry.status);
  const [category, setCategory] = useState(inquiry.category);
  const [item, setItem] = useState(inquiry.item);
  const [manager, setManager] = useState(inquiry.manager);
  const [memo, setMemo] = useState('');

  // 유저 관리의 실제 활성 멤버 목록에서 담당자 옵션 생성
  const managerOptions = useMemo(() => {
    const activeNames = MEMBERS.filter((m) => m.active).map((m) => m.name);
    return ['미배정', ...activeNames];
  }, []);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />
      <div className="relative bg-white rounded-xl w-[880px] max-h-[90vh] flex flex-col" style={{ maxWidth: '95vw' }}>
        {/* Head */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <div className="flex items-center gap-3">
            <span className="text-[14px] font-bold text-gray-900">티켓 #{inquiry.ticket}</span>
            <span className={`text-[11px] font-semibold px-2.5 py-0.5 rounded-full ${STATUS_STYLE[inquiry.status]}`}>{inquiry.status}</span>
          </div>
          <button onClick={onClose} className="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-gray-100 transition-colors cursor-pointer">
            <i className="ri-close-line text-gray-500 text-lg"></i>
          </button>
        </div>
        {/* Body */}
        <div className="flex flex-1 overflow-hidden">
          {/* Left */}
          <div className="flex-1 overflow-y-auto px-6 py-5 space-y-5 border-r border-gray-100">
            <div>
              <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-3">접수 정보</p>
              <div className="grid grid-cols-2 gap-2 text-[12px]">
                {[['구분', inquiry.category], ['항목', inquiry.item], ['접수일', inquiry.date], ['언어', inquiry.lang || 'KR']].map(([k, v]) => (
                  <div key={k} className="flex gap-2"><span className="text-gray-400 w-16 flex-shrink-0">{k}</span><span className="text-gray-700 font-medium">{v}</span></div>
                ))}
              </div>
            </div>
            <div>
              <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-3">신청자 정보</p>
              <div className="grid grid-cols-2 gap-2 text-[12px]">
                {[['회사명', inquiry.company], ['이름', inquiry.name], ['이메일', inquiry.email || '—'], ['연락처', inquiry.phone || '—']].map(([k, v]) => (
                  <div key={k} className="flex gap-2"><span className="text-gray-400 w-16 flex-shrink-0">{k}</span><span className="text-gray-700 font-medium">{v}</span></div>
                ))}
              </div>
            </div>
            <div>
              <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-2">문의 내용</p>
              <div className="bg-gray-50 rounded-lg p-3 text-[12px] text-gray-700 leading-relaxed">{inquiry.content || '내용 없음'}</div>
            </div>
          </div>
          {/* Right */}
          <div className="w-[240px] flex-shrink-0 px-5 py-5 space-y-4">
            <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider">처리 정보</p>
            <div>
              <label className="text-[11px] text-gray-500 mb-1 block">상태 변경</label>
              <select value={status} onChange={(e) => setStatus(e.target.value as InquiryStatus)} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] text-gray-700 outline-none focus:border-teal-400 cursor-pointer">
                {['신규', '처리중', '완료', '보류'].map((s) => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[11px] text-gray-500 mb-1 block">구분 변경</label>
              <select value={category} onChange={(e) => setCategory(e.target.value)} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] text-gray-700 outline-none focus:border-teal-400 cursor-pointer">
                {['제품', '컨설팅', 'R&D', '기타'].map((s) => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[11px] text-gray-500 mb-1 block">항목 변경</label>
              <select value={item} onChange={(e) => setItem(e.target.value)} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] text-gray-700 outline-none focus:border-teal-400 cursor-pointer">
                {['문의', '자료', '기타'].map((s) => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[11px] text-gray-500 mb-1 block">담당자 배정</label>
              <select value={manager} onChange={(e) => setManager(e.target.value)} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] text-gray-700 outline-none focus:border-teal-400 cursor-pointer">
                {managerOptions.map((m) => <option key={m}>{m}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[11px] text-gray-500 mb-1 block">처리 메모</label>
              <textarea value={memo} onChange={(e) => setMemo(e.target.value)} rows={5} className="w-full border border-gray-200 rounded-lg px-2.5 py-2 text-[12px] text-gray-700 outline-none focus:border-teal-400 resize-none" placeholder="처리 내용을 입력하세요..." />
            </div>
          </div>
        </div>
        {/* Footer */}
        <div className="flex items-center justify-between px-6 py-3.5 border-t border-gray-100">
          <span className="text-[11px] text-gray-400">접수일: {inquiry.date}</span>
          <div className="flex gap-2">
            <button onClick={onClose} className="px-4 py-1.5 rounded-lg border border-gray-200 text-[12px] text-gray-600 hover:bg-gray-50 transition-colors cursor-pointer whitespace-nowrap">닫기</button>
            <button onClick={() => onSave({ ...inquiry, status, category, item, manager })} className="px-4 py-1.5 rounded-lg bg-teal-500 text-white text-[12px] font-semibold hover:bg-teal-600 transition-colors cursor-pointer whitespace-nowrap">저장</button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function InquiryPage() {
  const [data, setData] = useState<Inquiry[]>(INQUIRIES);
  const [categoryFilter, setCategoryFilter] = useState('전체');
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [selectedInq, setSelectedInq] = useState<Inquiry | null>(null);

  const filtered = useMemo(() => {
    let list = data;
    if (categoryFilter !== '전체') list = list.filter((i) => i.category === categoryFilter);
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter((i) => i.ticket.toLowerCase().includes(q) || i.company.toLowerCase().includes(q) || i.name.toLowerCase().includes(q));
    }
    return list;
  }, [data, categoryFilter, search]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
  const pageData = filtered.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);

  const stats = useMemo(() => ({
    total: filtered.length,
    unassigned: filtered.filter((i) => i.manager === '미배정').length,
    processing: filtered.filter((i) => i.status === '처리중').length,
    done: filtered.filter((i) => i.status === '완료').length,
  }), [filtered]);

  const handleSave = (updated: Inquiry) => {
    setData((prev) => prev.map((i) => i.id === updated.id ? updated : i));
    setSelectedInq(null);
  };

  return (
    <div className="p-5 space-y-4">
      {/* Top bar */}
      <div className="bg-white border border-gray-100 rounded-lg px-4 py-3 flex items-center gap-3 flex-wrap">
        <div className="flex gap-1">
          {['전체', '제품', '컨설팅', 'R&D', '기타'].map((c) => (
            <button key={c} onClick={() => { setCategoryFilter(c); setPage(1); }}
              className={`px-3 py-1.5 rounded-lg text-[12px] font-medium transition-colors cursor-pointer whitespace-nowrap ${categoryFilter === c ? 'bg-[#1a1e2a] text-white' : 'text-gray-500 hover:bg-gray-100'}`}>{c}</button>
          ))}
        </div>
        <div className="flex items-center gap-2 ml-auto flex-wrap">
          <div className="flex items-center gap-1.5 border border-gray-200 rounded-lg px-3 py-1.5">
            <i className="ri-search-line text-gray-400 text-sm"></i>
            <input value={search} onChange={(e) => { setSearch(e.target.value); setPage(1); }} placeholder="티켓, 회사, 이름" className="text-[12px] text-gray-700 outline-none w-36 placeholder:text-gray-300" />
          </div>
          <button className="px-3 py-1.5 bg-teal-500 text-white text-[12px] font-semibold rounded-lg hover:bg-teal-600 transition-colors cursor-pointer whitespace-nowrap">조회</button>
        </div>
      </div>

      {/* Stats bar */}
      <div className="bg-white border border-gray-100 rounded-lg px-5 py-2.5 flex items-center justify-between flex-wrap gap-2">
        <div className="flex items-center gap-5 text-[12px] text-gray-500">
          <span>총 <strong className="text-gray-900">{stats.total}</strong>건</span>
          <span>미배정 <strong className="text-rose-500">{stats.unassigned}</strong>건</span>
          <span>처리중 <strong className="text-amber-500">{stats.processing}</strong>건</span>
          <span>완료 <strong className="text-teal-500">{stats.done}</strong>건</span>
        </div>
        <div className="flex items-center gap-1 text-[12px] text-gray-500">
          <button onClick={() => setPage(1)} disabled={page === 1} className="px-2 py-1 rounded hover:bg-gray-100 disabled:opacity-30 cursor-pointer whitespace-nowrap">≪</button>
          <button onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={page === 1} className="px-2 py-1 rounded hover:bg-gray-100 disabled:opacity-30 cursor-pointer whitespace-nowrap">&lt;</button>
          <span className="px-2 text-[12px]">{page} / {totalPages} Page</span>
          <button onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={page === totalPages} className="px-2 py-1 rounded hover:bg-gray-100 disabled:opacity-30 cursor-pointer whitespace-nowrap">&gt;</button>
          <button onClick={() => setPage(totalPages)} disabled={page === totalPages} className="px-2 py-1 rounded hover:bg-gray-100 disabled:opacity-30 cursor-pointer whitespace-nowrap">≫</button>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white border border-gray-100 rounded-lg overflow-x-auto">
        <table className="w-full min-w-[760px]">
          <thead>
            <tr className="bg-gray-50/70 border-b border-gray-100">
              {['티켓', '접수일', '회사', '이름', '구분', '항목', '상태', '담당자', '처리'].map((h) => (
                <th key={h} className="text-left px-4 py-2.5 text-[11px] font-semibold text-gray-400 whitespace-nowrap">{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {pageData.map((inq) => (
              <tr key={inq.id} className="border-b border-gray-50 hover:bg-gray-50/60 transition-colors">
                <td className="px-4 py-2.5">
                  <button onClick={() => setSelectedInq(inq)} className="text-[12px] font-mono text-teal-600 hover:text-teal-700 font-semibold cursor-pointer whitespace-nowrap">{inq.ticket}</button>
                </td>
                <td className="px-4 py-2.5 text-[12px] text-gray-500 whitespace-nowrap font-mono">{inq.date}</td>
                <td className="px-4 py-2.5 text-[12px] text-gray-700 whitespace-nowrap">{inq.company}</td>
                <td className="px-4 py-2.5 text-[12px] text-gray-700 whitespace-nowrap">{inq.name}</td>
                <td className="px-4 py-2.5">
                  <span className={`text-[11px] font-semibold px-2 py-0.5 rounded whitespace-nowrap ${TYPE_STYLE[inq.category] || 'bg-gray-100 text-gray-600'}`}>{inq.category}</span>
                </td>
                <td className="px-4 py-2.5">
                  <span className="text-[11px] font-semibold px-2 py-0.5 rounded bg-gray-100 text-gray-600 whitespace-nowrap">{inq.item}</span>
                </td>
                <td className="px-4 py-2.5">
                  <span className={`text-[11px] font-semibold px-2.5 py-0.5 rounded-full whitespace-nowrap ${STATUS_STYLE[inq.status]}`}>{inq.status}</span>
                </td>
                <td className="px-4 py-2.5 text-[12px] text-gray-500 whitespace-nowrap">{inq.manager}</td>
                <td className="px-4 py-2.5">
                  <select value={inq.status} onChange={(e) => setData((prev) => prev.map((i) => i.id === inq.id ? { ...i, status: e.target.value as InquiryStatus } : i))}
                    className="border border-gray-200 rounded px-2 py-1 text-[11px] text-gray-600 outline-none cursor-pointer">
                    {['신규', '처리중', '완료', '보류'].map((s) => <option key={s}>{s}</option>)}
                  </select>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {selectedInq && <InquiryModal inquiry={selectedInq} onClose={() => setSelectedInq(null)} onSave={handleSave} />}
    </div>
  );
}
