const TERMS_DATA = [
  { id: 't-privacy', name: '개인정보처리방침', version: 'v2.4', updatedAt: '2026-04-01', required: true, active: true },
  { id: 't-terms', name: '이용약관', version: 'v1.8', updatedAt: '2026-03-15', required: true, active: true },
  { id: 't-marketing', name: '마케팅 수신 동의', version: 'v1.2', updatedAt: '2026-01-10', required: false, active: true },
  { id: 't-thirdparty', name: '제3자 정보 제공 동의', version: 'v1.0', updatedAt: '2025-12-01', required: false, active: false },
];

interface AddTermModalProps {
  onClose: () => void;
  onAdd: (term: { id: string; name: string; version: string; updatedAt: string; required: boolean; active: boolean }, content: string) => void;
}

function AddTermModal({ onClose, onAdd }: AddTermModalProps) {
  const [name, setName] = useState('');
  const [required, setRequired] = useState(false);
  const [content, setContent] = useState('');
  const [saving, setSaving] = useState(false);

  const handleSubmit = () => {
    if (!name.trim()) return;
    setSaving(true);
    setTimeout(() => {
      const id = 't-custom-' + Date.now();
      const now = new Date().toISOString().slice(0, 10);
      onAdd({ id, name: name.trim(), version: 'v1.0', updatedAt: now, required, active: true }, content);
      setSaving(false);
      onClose();
    }, 600);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/30" onClick={onClose} />
      <div className="relative bg-white rounded-xl shadow-xl w-[560px] max-h-[85vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="flex items-center justify-between px-5 py-4 border-b border-gray-100">
          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 flex items-center justify-center bg-teal-50 rounded-lg">
              <i className="ri-file-add-line text-teal-600 text-base"></i>
            </div>
            <div>
              <h3 className="text-[14px] font-bold text-gray-800">새 약관 추가</h3>
              <p className="text-[11px] text-gray-400">추가 즉시 v1.0으로 등록됩니다.</p>
            </div>
          </div>
          <button onClick={onClose} className="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-gray-100 text-gray-400 cursor-pointer">
            <i className="ri-close-line text-base"></i>
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {/* 약관명 */}
          <div>
            <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">
              약관명 <span className="text-rose-500">*</span>
            </label>
            <input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="예: 위치정보 수집 동의"
              className="w-full border border-gray-200 rounded-lg px-3 py-2 text-[13px] text-gray-700 outline-none focus:border-teal-400 transition-colors"
              maxLength={60}
            />
            <p className="text-[11px] text-gray-400 mt-1">{name.length} / 60자</p>
          </div>

          {/* 필수 여부 */}
          <div>
            <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">동의 유형</label>
            <div className="flex gap-3">
              {[{ val: false, label: '선택 동의', desc: '사용자가 선택적으로 동의할 수 있습니다.' }, { val: true, label: '필수 동의', desc: '서비스 이용 시 반드시 동의해야 합니다.' }].map((opt) => (
                <label
                  key={String(opt.val)}
                  className={`flex-1 flex items-start gap-2.5 border rounded-lg p-3 cursor-pointer transition-colors ${required === opt.val ? 'border-teal-400 bg-teal-50/40' : 'border-gray-200 hover:bg-gray-50'}`}
                >
                  <input
                    type="radio"
                    name="term-required"
                    checked={required === opt.val}
                    onChange={() => setRequired(opt.val)}
                    className="mt-0.5 accent-teal-500 cursor-pointer"
                  />
                  <div>
                    <p className="text-[12px] font-semibold text-gray-700">{opt.label}</p>
                    <p className="text-[11px] text-gray-400 mt-0.5">{opt.desc}</p>
                  </div>
                </label>
              ))}
            </div>
          </div>

          {/* 약관 내용 */}
          <div>
            <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">약관 내용</label>
            <textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              rows={8}
              placeholder="제1조 (목적)&#10;본 약관은..."
              className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-[12px] text-gray-700 outline-none focus:border-teal-400 resize-none font-mono leading-relaxed transition-colors"
              maxLength={5000}
            />
            <p className="text-[11px] text-gray-400 mt-1">{content.length} / 5000자</p>
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between px-5 py-3.5 border-t border-gray-100 bg-gray-50/50">
          <p className="text-[11px] text-gray-400">저장 후 약관 목록에서 내용 편집이 가능합니다.</p>
          <div className="flex gap-2">
            <button
              onClick={onClose}
              className="px-4 py-2 border border-gray-200 rounded-lg text-[12px] text-gray-600 hover:bg-gray-100 cursor-pointer whitespace-nowrap transition-colors"
            >
              취소
            </button>
            <button
              onClick={handleSubmit}
              disabled={!name.trim() || saving}
              className={`px-4 py-2 rounded-lg text-[12px] font-semibold cursor-pointer whitespace-nowrap transition-colors ${name.trim() && !saving ? 'bg-teal-500 text-white hover:bg-teal-600' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
            >
              {saving ? '저장 중...' : '약관 추가'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

