const BLOG_CATEGORIES = ['보안 연구', '기술', '취약점', '연구', '솔루션', '컨설팅', 'R&D', '이벤트'];

type BlogModalProps = {
  post: Partial<BlogPost> | null;
  onClose: () => void;
  onSave: (post: BlogPost) => void;
  nextId: number;
};

function BlogPostModal({ post, onClose, onSave, nextId }: BlogModalProps) {
  const isNew = !post?.id;
  const today = new Date().toISOString().split('T')[0];
  const [form, setForm] = useState<BlogPost>({
    id: post?.id ?? nextId,
    title: post?.title ?? '',
    category: post?.category ?? '보안 연구',
    author: post?.author ?? '',
    status: post?.status ?? false,
    date: post?.date ?? today,
    content: post?.content ?? '',
    tags: post?.tags ?? '',
  });
  const [saved, setSaved] = useState(false);

  const handleChange = (key: keyof BlogPost, value: string | boolean) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const handleSave = () => {
    if (!form.title.trim()) return;
    onSave(form);
    setSaved(true);
    setTimeout(() => { setSaved(false); onClose(); }, 1200);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" onClick={onClose}>
      <div
        className="bg-white rounded-2xl shadow-xl w-full max-w-2xl mx-4 flex flex-col"
        style={{ maxHeight: '90vh' }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <div className="flex items-center gap-2">
            <span className="text-[11px] font-semibold px-2 py-0.5 rounded-full bg-teal-50 text-teal-700">기술 블로그</span>
            <h2 className="text-[15px] font-bold text-gray-800">{isNew ? '새 포스트 작성' : '포스트 편집'}</h2>
          </div>
          <button onClick={onClose} className="w-7 h-7 flex items-center justify-center rounded-full hover:bg-gray-100 text-gray-400 cursor-pointer">
            <i className="ri-close-line text-[16px]"></i>
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto px-6 py-5 space-y-4">
          {/* Title */}
          <div>
            <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">제목 <span className="text-rose-400">*</span></label>
            <input
              value={form.title}
              onChange={(e) => handleChange('title', e.target.value)}
              placeholder="포스트 제목을 입력하세요"
              className="w-full border border-gray-200 rounded-lg px-3 py-2 text-[13px] text-gray-800 outline-none focus:border-teal-400 transition-colors"
            />
          </div>

          {/* Category / Author / Status / Date */}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">카테고리</label>
              <select
                value={form.category}
                onChange={(e) => handleChange('category', e.target.value)}
                className="w-full border border-gray-200 rounded-lg px-3 py-2 text-[12px] text-gray-700 outline-none focus:border-teal-400 bg-white cursor-pointer"
              >
                {BLOG_CATEGORIES.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">작성자</label>
              <input
                value={form.author}
                onChange={(e) => handleChange('author', e.target.value)}
                placeholder="작성자 이름"
                className="w-full border border-gray-200 rounded-lg px-3 py-2 text-[12px] text-gray-700 outline-none focus:border-teal-400"
              />
            </div>
            <div>
              <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">공개 상태</label>
              <div className="flex gap-2 mt-1">
                {[{ label: '게시됨', value: true }, { label: '초안', value: false }].map(({ label, value }) => (
                  <button
                    key={label}
                    onClick={() => handleChange('status', value)}
                    className={`px-3 py-1.5 rounded-lg text-[12px] font-semibold border transition-colors cursor-pointer whitespace-nowrap ${form.status === value ? (value ? 'bg-teal-500 text-white border-teal-500' : 'bg-amber-500 text-white border-amber-500') : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}
                  >{label}</button>
                ))}
              </div>
            </div>
            <div>
              <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">등록일</label>
              <input
                type="date"
                value={form.date}
                onChange={(e) => handleChange('date', e.target.value)}
                className="w-full border border-gray-200 rounded-lg px-3 py-2 text-[12px] text-gray-700 outline-none focus:border-teal-400"
              />
            </div>
          </div>

          {/* Content */}
          <div>
            <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">본문 내용</label>
            <textarea
              value={form.content}
              onChange={(e) => handleChange('content', e.target.value)}
              rows={6}
              placeholder="포스트 내용을 입력하세요..."
              className="w-full border border-gray-200 rounded-lg px-3 py-2 text-[12px] text-gray-700 outline-none focus:border-teal-400 resize-none leading-relaxed"
            />
          </div>

          {/* Tags */}
          <div>
            <label className="text-[11px] font-semibold text-gray-500 mb-1.5 block">태그 <span className="text-gray-400 font-normal">(쉼표로 구분)</span></label>
            <input
              value={form.tags}
              onChange={(e) => handleChange('tags', e.target.value)}
              placeholder="예: 모바일보안, AppSuit, 취약점"
              className="w-full border border-gray-200 rounded-lg px-3 py-2 text-[12px] text-gray-700 outline-none focus:border-teal-400"
            />
            {form.tags && (
              <div className="flex flex-wrap gap-1 mt-2">
                {form.tags.split(',').map((t) => t.trim()).filter(Boolean).map((tag) => (
                  <span key={tag} className="px-2 py-0.5 rounded-full bg-teal-50 text-teal-700 text-[11px] font-medium">{tag}</span>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between px-6 py-4 border-t border-gray-100 bg-gray-50/60 rounded-b-2xl">
          <span className="text-[11px] text-gray-400">
            {saved ? '✅ 저장되었습니다.' : `포스트 ID: #${String(form.id).padStart(4, '0')}`}
          </span>
          <div className="flex gap-2">
            <button onClick={onClose} className="px-4 py-1.5 bg-white border border-gray-200 text-gray-600 text-[12px] font-semibold rounded-lg hover:bg-gray-50 cursor-pointer whitespace-nowrap">취소</button>
            <button
              onClick={handleSave}
              disabled={!form.title.trim()}
              className={`px-4 py-1.5 text-white text-[12px] font-semibold rounded-lg cursor-pointer whitespace-nowrap transition-colors ${form.title.trim() ? 'bg-teal-500 hover:bg-teal-600' : 'bg-gray-300 cursor-not-allowed'}`}
            >
              {saved ? '✅ 저장됨' : (isNew ? '📝 포스트 발행' : '💾 수정 저장')}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function SaveRow() {
  const [saved, setSaved] = useState(false);
  const handleSave = () => { setSaved(true); setTimeout(() => setSaved(false), 2000); };
  return (
    <div className="flex items-center justify-between pt-4 mt-4 border-t border-gray-100">
      <span className="text-[11px] text-gray-400">{saved ? '✅ 저장되었습니다.' : '📋 최근 저장: 2026-04-08 14:32 김민준'}</span>
      <button onClick={handleSave} className="px-4 py-1.5 bg-teal-500 text-white text-[12px] font-semibold rounded-lg hover:bg-teal-600 cursor-pointer whitespace-nowrap">💾 저장</button>
    </div>
  );
}

