import { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { useContactPopup, ContactPopupType } from './ContactPopupContext';

const FORM_URL = 'https://readdy.ai/api/form/d70th4b2m2156g4s73f0';

const documentOptions = [
  '제품 소개서',
  '도입 제안서',
  '가격 문의',
  '데모 시연 신청',
];

const PAGE_CONTEXT_MAP: Record<string, string> = {
  '/products/appsuit': 'AppSuit 시리즈',
  '/products/appsuit-premium': 'AppSuit Premium',
  '/products/appsuit-air': 'AppSuit Air',
  '/products/appsuit-keypad': 'AppSuit Keypad',
  '/products/appsuit-av': 'AppSuit AV',
  '/products/appsuit-remoteblock': 'AppSuit RemoteBlock',
  '/products/appsuit-macroblock': 'AppSuit MacroBlock',
  '/products/appsuit-anticapture': 'AppSuit Anti-Capture',
  '/products/appsuit-radar': 'AppSuit Radar',
  '/products/appsuit-vpnblock': 'AppSuit VPNBlock',
  '/products/appsuit-unit': 'AppSuit Unit',
  '/products/appsuit-hybrid': 'AppSuit Hybrid',
  '/products/cyber-drill': 'Cyber Drill',
  '/consulting/pentest': '모의해킹',
  '/consulting/red-team': '레드팀',
  '/rnd': 'R&D 서비스',
  '/consulting/security-consulting': '보안 컨설팅',
};

const PRIVACY_POLICY_TEXT = `스틸리언은 제품 문의, 기술 상담 및 서비스 제공을 위해 아래와 같이 개인정보를 수집·이용합니다. 수집된 정보는 명시된 목적 외에는 사용되지 않으며, 관련 법령을 준수하여 안전하게 관리됩니다.

1. 수집·이용 목적
제품·서비스 문의 응대 / 기술 지원 및 상담 / 자료 요청 회신 / 고객 요청사항 처리 및 민원 대응 / 후속 문의 대응 및 서비스 품질 개선

2. 수집 항목
• 필수: 이름, 회사명, 이메일 주소
• 선택: 전화번호 (미입력 시 서비스 이용 제한 없음)

3. 보유 및 이용기간
수집 목적 달성 시까지 보관 후 지체 없이 파기. 단, 관계 법령에 따라 보존이 필요한 경우 해당 기간 보관 (예: 소비자 분쟁 처리 기록 3년).

4. 제3자 제공
원칙적으로 외부 제공 없음. 법령에 의거하거나 사전 동의 있는 경우에 한해 제공 가능.

5. 처리 위탁
원활한 서비스 제공을 위해 일부 업무를 외부 전문업체에 위탁할 수 있으며, 관련 법령에 따라 안전하게 관리합니다.

6. 동의 거부 권리
개인정보 수집·이용에 대한 동의를 거부할 권리가 있습니다. 단, 필수 항목 거부 시 문의 접수 및 답변 제공이 제한될 수 있습니다.`;

export default function ContactPopup() {
  const { isOpen, popupType, closePopup, openPopup } = useContactPopup();
  const location = useLocation();
  const [activeTab, setActiveTab] = useState<ContactPopupType>(popupType);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [message, setMessage] = useState('');
  const [privacyAgreed, setPrivacyAgreed] = useState(false);
  const [pageProduct, setPageProduct] = useState('');
  const MESSAGE_LIMIT = 500;

  useEffect(() => {
    const matched = PAGE_CONTEXT_MAP[location.pathname] ?? '';
    setPageProduct(matched);
  }, [location.pathname]);

  useEffect(() => {
    setActiveTab(popupType);
  }, [popupType]);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
      setSubmitStatus('idle');
      setMessage('');
      setPrivacyAgreed(false);
    }
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  const handleTabChange = (tab: ContactPopupType) => {
    setActiveTab(tab);
    setSubmitStatus('idle');
    openPopup(tab);
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (submitStatus === 'loading' || !privacyAgreed) return;
    const form = e.currentTarget;
    if (message.length > MESSAGE_LIMIT) return;

    setSubmitStatus('loading');
    try {
      const formData = new FormData(form);
      const body = new URLSearchParams();
      formData.forEach((value, key) => { body.append(key, value.toString()); });

      const res = await fetch(FORM_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: body.toString(),
      });
      if (res.ok) {
        setSubmitStatus('success');
        form.reset();
        setMessage('');
        setPrivacyAgreed(false);
      } else {
        setSubmitStatus('error');
      }
    } catch {
      setSubmitStatus('error');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-6">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={closePopup} />

      {/* Modal — 넓은 2컬럼 레이아웃 */}
      <div className="relative bg-white rounded-2xl w-full max-w-4xl">
        {/* Header */}
        <div className="flex items-center justify-between px-8 pt-6 pb-4 border-b border-gray-100">
          <div className="flex items-center gap-4">
            <div>
              <h2 className="text-lg font-bold text-gray-900">스틸리언에 문의하세요</h2>
            </div>
            {pageProduct && (
              <div className="flex items-center gap-1.5 bg-teal-50 border border-teal-200 rounded-lg px-3 py-1.5">
                <i className="ri-price-tag-3-line text-teal-600 text-xs shrink-0"></i>
                <span className="text-xs text-teal-700 font-medium whitespace-nowrap">관련 제품/서비스:</span>
                <span className="text-xs text-teal-800 font-bold whitespace-nowrap">{pageProduct}</span>
              </div>
            )}
          </div>
          <button
            onClick={closePopup}
            className="w-9 h-9 flex items-center justify-center rounded-full hover:bg-gray-100 transition-colors cursor-pointer shrink-0"
          >
            <i className="ri-close-line text-xl text-gray-500"></i>
          </button>
        </div>

        {/* Tab Switcher */}
        <div className="px-8 pt-4 pb-0">
          <div className="inline-flex bg-gray-100 rounded-full p-1">
            <button
              type="button"
              onClick={() => handleTabChange('inquiry')}
              className={`px-8 py-2 rounded-full text-sm font-semibold transition-all whitespace-nowrap cursor-pointer ${
                activeTab === 'inquiry' ? 'bg-teal-600 text-white' : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              <i className="ri-chat-3-line mr-1.5"></i>문의하기
            </button>
            <button
              type="button"
              onClick={() => handleTabChange('document')}
              className={`px-8 py-2 rounded-full text-sm font-semibold transition-all whitespace-nowrap cursor-pointer ${
                activeTab === 'document' ? 'bg-teal-600 text-white' : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              <i className="ri-file-download-line mr-1.5"></i>자료 요청
            </button>
          </div>
        </div>

        {/* Success State */}
        {submitStatus === 'success' ? (
          <div className="px-8 py-16 text-center">
            <div className="w-16 h-16 flex items-center justify-center bg-teal-50 rounded-full mx-auto mb-4">
              <i className="ri-checkbox-circle-line text-3xl text-teal-600"></i>
            </div>
            <h3 className="text-lg font-bold text-gray-900 mb-2">
              {activeTab === 'inquiry' ? '문의가 접수되었습니다' : '자료 요청이 접수되었습니다'}
            </h3>
            <p className="text-sm text-gray-500 mb-6 leading-relaxed">
              입력하신 이메일로 확인 메일을 발송했습니다.<br />
              평균 24시간 이내 전담 담당자가 연락드립니다.
            </p>
            <button
              onClick={closePopup}
              className="inline-block bg-teal-600 text-white px-10 py-2.5 rounded-lg text-sm font-semibold hover:bg-teal-700 transition-colors cursor-pointer whitespace-nowrap"
            >
              확인
            </button>
          </div>
        ) : (
          <form
            data-readdy-form
            id="contact-popup-form"
            onSubmit={handleSubmit}
            className="px-8 py-5"
          >
            <input type="hidden" name="문의유형" value={activeTab === 'inquiry' ? '문의하기' : '자료 요청'} />
            {pageProduct && <input type="hidden" name="관련제품서비스" value={pageProduct} />}

            {/* 2컬럼 레이아웃 */}
            <div className="grid grid-cols-2 gap-6">
              {/* 왼쪽: 입력 필드 */}
              <div className="space-y-3.5">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-xs font-semibold text-gray-700 mb-1.5">
                      이름 <span className="text-red-500">*</span>
                    </label>
                    <input
                      type="text"
                      name="이름"
                      required
                      placeholder="홍길동"
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:border-teal-400 transition-colors"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-700 mb-1.5">
                      회사명 <span className="text-red-500">*</span>
                    </label>
                    <input
                      type="text"
                      name="회사명"
                      required
                      placeholder="(주)스틸리언"
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:border-teal-400 transition-colors"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-semibold text-gray-700 mb-1.5">
                    이메일 <span className="text-red-500">*</span>
                  </label>
                  <input
                    type="email"
                    name="email"
                    required
                    placeholder="example@company.com"
                    className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:border-teal-400 transition-colors"
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-gray-700 mb-1.5">연락처</label>
                  <input
                    type="tel"
                    name="연락처"
                    placeholder="010-0000-0000"
                    className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:border-teal-400 transition-colors"
                  />
                </div>

                {activeTab === 'document' && (
                  <div>
                    <label className="block text-xs font-semibold text-gray-700 mb-1.5">
                      요청 자료 <span className="text-red-500">*</span>
                    </label>
                    <select
                      name="요청자료"
                      required
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:border-teal-400 transition-colors bg-white cursor-pointer"
                    >
                      <option value="">자료를 선택해주세요</option>
                      {documentOptions.map((opt) => (
                        <option key={opt} value={opt}>{opt}</option>
                      ))}
                    </select>
                  </div>
                )}

                {/* 문의하기 탭일 때 메시지 필드를 왼쪽에 배치 */}
                {activeTab === 'inquiry' && (
                  <div>
                    <label className="block text-xs font-semibold text-gray-700 mb-1.5">
                      문의 내용 <span className="text-red-500">*</span>
                      <span className="ml-2 text-xs font-normal text-gray-400">({message.length}/{MESSAGE_LIMIT}자)</span>
                    </label>
                    <textarea
                      name="문의내용"
                      required
                      rows={5}
                      value={message}
                      onChange={(e) => { if (e.target.value.length <= MESSAGE_LIMIT) setMessage(e.target.value); }}
                      placeholder="문의하실 내용을 입력해주세요."
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm resize-none focus:outline-none focus:border-teal-400 transition-colors"
                    />
                    {message.length >= MESSAGE_LIMIT && (
                      <p className="text-xs text-red-500 mt-1">최대 {MESSAGE_LIMIT}자까지 입력 가능합니다.</p>
                    )}
                  </div>
                )}
              </div>

              {/* 오른쪽: 자료요청 메시지 + 개인정보 동의 */}
              <div className="space-y-3.5 flex flex-col">
                {activeTab === 'document' && (
                  <div>
                    <label className="block text-xs font-semibold text-gray-700 mb-1.5">
                      요청 목적 <span className="text-red-500">*</span>
                      <span className="ml-2 text-xs font-normal text-gray-400">({message.length}/{MESSAGE_LIMIT}자)</span>
                    </label>
                    <textarea
                      name="요청목적"
                      required
                      rows={4}
                      value={message}
                      onChange={(e) => { if (e.target.value.length <= MESSAGE_LIMIT) setMessage(e.target.value); }}
                      placeholder="자료 요청 목적 및 사용 계획을 간략히 입력해주세요."
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm resize-none focus:outline-none focus:border-teal-400 transition-colors"
                    />
                    {message.length >= MESSAGE_LIMIT && (
                      <p className="text-xs text-red-500 mt-1">최대 {MESSAGE_LIMIT}자까지 입력 가능합니다.</p>
                    )}
                  </div>
                )}

                {/* 개인정보 수집·이용 동의 */}
                <div className="flex-1 flex flex-col border border-gray-200 rounded-xl overflow-hidden">
                  <div className="bg-gray-50 px-4 py-2.5 border-b border-gray-200 flex items-center gap-2 shrink-0">
                    <i className="ri-shield-user-line text-teal-600 text-sm"></i>
                    <span className="text-xs font-semibold text-gray-700">개인정보 수집·이용 동의</span>
                    <span className="text-xs text-red-500 font-medium">(필수)</span>
                  </div>
                  {/* 동의서 내용 — 스크롤 없이 전체 표시 */}
                  <div className="flex-1 px-4 py-3 bg-white text-xs text-gray-600 leading-relaxed whitespace-pre-line overflow-y-auto" style={{ minHeight: activeTab === 'document' ? '120px' : '220px', maxHeight: activeTab === 'document' ? '180px' : '300px' }}>
                    {PRIVACY_POLICY_TEXT}
                  </div>
                  {/* 동의 체크박스 */}
                  <div className="bg-gray-50 border-t border-gray-200 px-4 py-3 shrink-0">
                    <label className="flex items-center gap-2.5 cursor-pointer group">
                      <div className="relative flex-shrink-0">
                        <input
                          type="checkbox"
                          checked={privacyAgreed}
                          onChange={(e) => setPrivacyAgreed(e.target.checked)}
                          className="sr-only"
                        />
                        <div
                          className={`w-5 h-5 rounded flex items-center justify-center border-2 transition-all ${
                            privacyAgreed
                              ? 'bg-teal-600 border-teal-600'
                              : 'bg-white border-gray-300 group-hover:border-teal-400'
                          }`}
                        >
                          {privacyAgreed && <i className="ri-check-line text-white text-xs"></i>}
                        </div>
                      </div>
                      <span className="text-xs text-gray-700 leading-relaxed">
                        개인정보 수집·이용 목적, 항목 및 보유기간을 확인하였으며, 이에 <strong className="text-gray-900">동의합니다.</strong>
                      </span>
                    </label>
                  </div>
                </div>

                {submitStatus === 'error' && (
                  <div className="bg-red-50 border border-red-200 rounded-lg px-4 py-2.5">
                    <p className="text-xs text-red-600">제출 중 오류가 발생했습니다. 잠시 후 다시 시도해주세요.</p>
                  </div>
                )}

                {/* 제출 버튼 */}
                <button
                  type="submit"
                  disabled={submitStatus === 'loading' || !privacyAgreed}
                  className={`w-full py-3 rounded-lg text-sm font-bold transition-colors whitespace-nowrap ${
                    privacyAgreed
                      ? 'bg-teal-600 hover:bg-teal-700 text-white cursor-pointer'
                      : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {submitStatus === 'loading' ? (
                    <span className="flex items-center justify-center gap-2">
                      <i className="ri-loader-4-line animate-spin"></i> 처리 중...
                    </span>
                  ) : (
                    activeTab === 'inquiry' ? '문의 접수하기' : '자료 요청하기'
                  )}
                </button>
                {!privacyAgreed && (
                  <p className="text-center text-xs text-gray-400 -mt-1">
                    개인정보 수집·이용에 동의하셔야 제출할 수 있습니다.
                  </p>
                )}
              </div>
            </div>
          </form>
        )}
      </div>
    </div>
  );
}
