import { useEffect, useRef } from 'react';

const whyItems = [
  {
    icon: 'ri-shield-star-line',
    color: 'text-teal-400',
    bg: 'bg-teal-500/10 border-teal-500/20',
    title: '해커가 보안을 설계',
    desc: '실제 침투 경험을 바탕으로 개발된 솔루션. 이론이 아닌 실전 공격 패턴에서 출발한 차별화된 방어 기술을 제공합니다.',
    stat: '11+',
    statLabel: '년 실전 경력',
  },
  {
    icon: 'ri-flask-line',
    color: 'text-orange-400',
    bg: 'bg-orange-500/10 border-orange-500/20',
    title: '끊임없는 연구개발',
    desc: '사이버 위협은 매일 진화합니다. 스틸리언은 최신 공격 기법을 선제적으로 연구하고 이를 즉시 제품과 서비스에 반영합니다.',
    stat: '100%',
    statLabel: '자체 기술 개발',
  },
  {
    icon: 'ri-user-heart-line',
    color: 'text-blue-400',
    bg: 'bg-blue-500/10 border-blue-500/20',
    title: '고객 맞춤 솔루션',
    desc: '금융, 게임, 공공, 헬스케어 — 산업별 규제와 환경을 깊이 이해하고 각 기업에 최적화된 보안 전략과 기술을 제공합니다.',
    stat: '500+',
    statLabel: '고객사 레퍼런스',
  },
];

export default function About() {
  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('opacity-100', 'translate-y-0');
            entry.target.classList.remove('opacity-0', 'translate-y-6');
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.05, rootMargin: '0px 0px -20px 0px' }
    );
    cardRefs.current.forEach((el) => {
      if (!el) return;
      const rect = el.getBoundingClientRect();
      if (rect.top < window.innerHeight && rect.bottom > 0) {
        el.classList.add('opacity-100', 'translate-y-0');
        el.classList.remove('opacity-0', 'translate-y-6');
      } else {
        observer.observe(el);
      }
    });
    return () => observer.disconnect();
  }, []);

  return (
    <section id="why" className="py-7 bg-white">
      <div className="max-w-content mx-auto px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-8">
          <h2 className="text-3xl md:text-4xl font-black text-gray-900 mb-4">
            스틸리언이 다른 이유
          </h2>
          <p className="text-base text-gray-500 max-w-xl mx-auto leading-relaxed">
            실제 해킹 경험에서 나온 보안. 이론이 아닌 현장이 만든 솔루션입니다.
          </p>
        </div>

        {/* Cards */}
        <div className="grid md:grid-cols-3 gap-6">
          {whyItems.map((item, i) => (
            <div
              key={i}
              ref={(el) => { cardRefs.current[i] = el; }}
              className="opacity-0 translate-y-6 transition-all duration-700 bg-white border border-gray-100 rounded-2xl p-7 hover:border-teal-200 hover:shadow-lg transition-shadow group"
              style={{ transitionDelay: `${i * 120}ms` }}
            >
              <div className={`w-12 h-12 flex items-center justify-center rounded-xl border mb-5 ${item.bg}`}>
                <i className={`${item.icon} text-2xl ${item.color}`}></i>
              </div>
              <h3 className="text-lg font-bold text-gray-900 mb-3">{item.title}</h3>
              <p className="text-sm text-gray-600 leading-relaxed mb-5">{item.desc}</p>
              <div className="border-t border-gray-100 pt-4 flex items-baseline gap-2">
                <span className="text-2xl font-black text-gray-900">{item.stat}</span>
                <span className="text-xs text-gray-500">{item.statLabel}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
