import { Link, useLocation } from 'react-router-dom';

const appSuitTabs = [
  { label: 'AppSuit', path: '/products/appsuit' },
  { label: 'Premium', path: '/products/appsuit-premium' },
  { label: 'Air', path: '/products/appsuit-air' },
  { label: 'Keypad', path: '/products/appsuit-keypad' },
  { label: 'AV', path: '/products/appsuit-av' },
  { label: 'RemoteBlock', path: '/products/appsuit-remoteblock' },
  { label: 'MacroBlock', path: '/products/appsuit-macroblock' },
  { label: 'Anti-Capture', path: '/products/appsuit-anticapture' },
  { label: 'Radar', path: '/products/appsuit-radar' },
];

const otherTabs = [
  { label: 'Cyber Drill', path: '/products/cyber-drill' },
];

export default function ProductSubNav() {
  const { pathname } = useLocation();

  const renderTab = (tab: { label: string; path: string }) => {
    const isActive = pathname === tab.path;
    return (
      <Link
        key={tab.path}
        to={tab.path}
        className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all duration-200 whitespace-nowrap cursor-pointer border ${
          isActive
            ? 'bg-teal-500 text-white border-teal-400 shadow-[0_0_16px_rgba(20,184,166,0.5)]'
            : 'text-white/70 hover:text-white hover:bg-white/15 border-transparent hover:border-white/20'
        }`}
      >
        {tab.label}
      </Link>
    );
  };

  return (
    <div className="w-full overflow-x-auto scrollbar-hide">
      <div className="flex flex-wrap justify-center items-center bg-black/40 backdrop-blur-xl rounded-xl border-2 border-white/25 overflow-hidden p-1 gap-0.5">
        {appSuitTabs.map(renderTab)}

        {/* 구분선 */}
        <div className="flex items-center mx-4 self-stretch">
          <div className="w-px h-6 bg-white/50 rounded-full" />
        </div>

        {otherTabs.map(renderTab)}
      </div>
    </div>
  );
}
