import { useRef, useEffect, useState, useCallback } from 'react';

const VALUES = [
  {
    keyword: '정직',
    desc: '매사에 정직하고 양심을 따르는 것은 모든 일의 기본입니다.',
  },
  {
    keyword: '소통',
    desc: '예의를 기반으로 정직하게 소통하는 것은 신뢰 형성의 길입니다.',
  },
  {
    keyword: '고객중심',
    desc: '고객의 성공은 우리의 기준이자 성장과 혁신의 원동력입니다.',
  },
  {
    keyword: '실험정신',
    desc: '아이디어를 행동으로 옮기는 실험을 통해 혁신을 이룩합니다.',
  },
  {
    keyword: '프로정신',
    desc: '맡은 일을 끝까지 완수하는 것은 나와 회사, 고객을 위한 일입니다.',
  },
];

// Canvas size & pentagon params
const W = 460;
const H = 420;
const CX = 230;
const CY = 210;
const R = 130;
const LABEL_OFFSET = 42;
const TEAL = '#0d9488';
const TEAL_LIGHT = 'rgba(13,148,136,0.12)';
const TEAL_SPOKE = 'rgba(13,148,136,0.35)';

function getVertex(i: number) {
  const angle = -Math.PI / 2 + (i * 2 * Math.PI) / 5;
  return {
    x: CX + R * Math.cos(angle),
    y: CY + R * Math.sin(angle),
    angle,
  };
}

const VERTICES = [0, 1, 2, 3, 4].map(getVertex);

function getLabelPos(i: number) {
  const v = VERTICES[i];
  return {
    x: v.x + LABEL_OFFSET * Math.cos(v.angle),
    y: v.y + LABEL_OFFSET * Math.sin(v.angle),
  };
}

export default function CoreValuesPentagon() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);

  const drawCanvas = useCallback((active: number | null) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, W, H);

    // ── Concentric inner pentagons (decorative) ──
    [0.33, 0.66].forEach((scale) => {
      ctx.beginPath();
      VERTICES.forEach((v, i) => {
        const vx = CX + (v.x - CX) * scale;
        const vy = CY + (v.y - CY) * scale;
        if (i === 0) ctx.moveTo(vx, vy);
        else ctx.lineTo(vx, vy);
      });
      ctx.closePath();
      ctx.strokeStyle = '#eef0f4';
      ctx.lineWidth = 1;
      ctx.stroke();
    });

    // ── Outer pentagon ──
    ctx.beginPath();
    VERTICES.forEach((v, i) => {
      if (i === 0) ctx.moveTo(v.x, v.y);
      else ctx.lineTo(v.x, v.y);
    });
    ctx.closePath();
    ctx.strokeStyle = '#d1d5db';
    ctx.lineWidth = 1.5;
    ctx.stroke();

    // ── Spoke lines ──
    VERTICES.forEach((v, i) => {
      ctx.beginPath();
      ctx.moveTo(CX, CY);
      ctx.lineTo(v.x, v.y);
      ctx.strokeStyle = active === i ? TEAL_SPOKE : '#eff1f5';
      ctx.lineWidth = 1.5;
      ctx.stroke();
    });

    // ── Active highlight: fill sector + highlight edges ──
    if (active !== null) {
      const prev = (active + 4) % 5;
      const next = (active + 1) % 5;

      // Filled sector
      ctx.beginPath();
      ctx.moveTo(CX, CY);
      ctx.lineTo(VERTICES[prev].x, VERTICES[prev].y);
      ctx.lineTo(VERTICES[active].x, VERTICES[active].y);
      ctx.lineTo(VERTICES[next].x, VERTICES[next].y);
      ctx.closePath();
      ctx.fillStyle = TEAL_LIGHT;
      ctx.fill();

      // Highlighted edges
      ctx.beginPath();
      ctx.moveTo(VERTICES[prev].x, VERTICES[prev].y);
      ctx.lineTo(VERTICES[active].x, VERTICES[active].y);
      ctx.lineTo(VERTICES[next].x, VERTICES[next].y);
      ctx.strokeStyle = TEAL;
      ctx.lineWidth = 2.5;
      ctx.lineJoin = 'round';
      ctx.stroke();
    }

    // ── Vertex dots ──
    VERTICES.forEach((v, i) => {
      const isActive = active === i;

      if (isActive) {
        // Outer ring
        ctx.beginPath();
        ctx.arc(v.x, v.y, 13, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(13,148,136,0.12)';
        ctx.fill();

        ctx.beginPath();
        ctx.arc(v.x, v.y, 8, 0, Math.PI * 2);
        ctx.fillStyle = TEAL;
        ctx.fill();
      } else {
        ctx.beginPath();
        ctx.arc(v.x, v.y, 5, 0, Math.PI * 2);
        ctx.fillStyle = '#9ca3af';
        ctx.fill();

        ctx.beginPath();
        ctx.arc(v.x, v.y, 5, 0, Math.PI * 2);
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
    });

    // ── Center dot ──
    ctx.beginPath();
    ctx.arc(CX, CY, 4, 0, Math.PI * 2);
    ctx.fillStyle = '#d1d5db';
    ctx.fill();
  }, []);

  useEffect(() => {
    drawCanvas(activeIndex);
  }, [activeIndex, drawCanvas]);

  return (
    <div className="flex flex-col lg:flex-row gap-6 items-center w-full">
      {/* ── Left: Pentagon diagram ── */}
      <div
        className="relative shrink-0"
        style={{ width: W, height: H }}
      >
        <canvas
          ref={canvasRef}
          width={W}
          height={H}
          className="absolute inset-0"
        />

        {VALUES.map((v, i) => {
          const pos = getLabelPos(i);
          const isActive = activeIndex === i;

          return (
            <div
              key={i}
              style={{
                position: 'absolute',
                left: `${(pos.x / W) * 100}%`,
                top: `${(pos.y / H) * 100}%`,
                transform: 'translate(-50%, -50%)',
                cursor: 'pointer',
                textAlign: 'center',
                userSelect: 'none',
                zIndex: 10,
              }}
              onMouseEnter={() => setActiveIndex(i)}
              onMouseLeave={() => setActiveIndex(null)}
            >
              <p
                className={`text-sm font-bold whitespace-nowrap leading-tight transition-colors duration-200 ${
                  isActive ? 'text-teal-600' : 'text-gray-700'
                }`}
              >
                {v.keyword}
              </p>
            </div>
          );
        })}
      </div>

      {/* ── Right: Description list ── */}
      <div className="flex-1 w-full">
        {VALUES.map((v, i) => {
          const isActive = activeIndex === i;
          return (
            <div
              key={i}
              onMouseEnter={() => setActiveIndex(i)}
              onMouseLeave={() => setActiveIndex(null)}
              className={`py-4 border-b border-gray-100 last:border-b-0 cursor-default transition-all duration-200 px-3 rounded-lg ${
                isActive ? 'bg-teal-50' : 'hover:bg-gray-50/50'
              }`}
            >
              <p
                className={`text-sm leading-relaxed transition-colors duration-200 whitespace-nowrap ${
                  isActive ? 'text-teal-700 font-medium' : 'text-gray-500'
                }`}
              >
                {v.desc}
              </p>
            </div>
          );
        })}
      </div>
    </div>
  );
}
