import { useState } from 'react';
import AdminSidebar from './components/AdminSidebar';
import DashboardPage from './components/DashboardPage';
import InquiryPage from './components/InquiryPage';
import StatsPage from './components/StatsPage';
import MemberPage from './components/MemberPage';
import PopupPage from './components/PopupPage';
import ContentPage from './components/ContentPage';
import SettingsPage from './components/SettingsPage';
import type { ActivePage } from './types';

const PAGE_TITLES: Record<ActivePage, string> = {
  dashboard: '대시보드',
  inquiry: '문의 관리',
  stats: '통계 분석',
  member: '유저 관리',
  popup: '팝업·배너 관리',
  content: '콘텐츠 관리',
  settings: '설정',
};

export default function AdminConsolePage() {
  const [activePage, setActivePage] = useState<ActivePage>('dashboard');

  const renderPage = () => {
    switch (activePage) {
      case 'dashboard': return <DashboardPage />;
      case 'inquiry': return <InquiryPage />;
      case 'stats': return <StatsPage />;
      case 'member': return <MemberPage />;
      case 'popup': return <PopupPage />;
      case 'content': return <ContentPage />;
      case 'settings': return <SettingsPage />;
      default: return <DashboardPage />;
    }
  };

  const isFullHeight = activePage === 'content' || activePage === 'settings';

  return (
    <div className="min-h-screen bg-[#f5f6fa] flex" style={{ fontFamily: "'Inter', 'Pretendard', sans-serif" }}>
      <AdminSidebar activePage={activePage} onNavigate={setActivePage} inquiryCount={7} />

      <div className="flex-1 min-w-0 flex flex-col overflow-hidden">
        {/* Top header */}
        <div className="h-[52px] bg-white border-b border-gray-100 flex items-center px-5 flex-shrink-0">
          <h1 className="text-[14px] font-bold text-gray-900">{PAGE_TITLES[activePage]}</h1>
          <div className="ml-auto flex items-center gap-3">
            <span className="text-[12px] text-gray-400">2026-04-15</span>
            <button className="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-gray-100 transition-colors cursor-pointer">
              <i className="ri-notification-3-line text-gray-500 text-sm"></i>
            </button>
            <button className="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-gray-100 transition-colors cursor-pointer">
              <i className="ri-question-line text-gray-500 text-sm"></i>
            </button>
          </div>
        </div>

        {/* Page content */}
        <div className={`flex-1 ${isFullHeight ? 'overflow-hidden flex flex-col' : 'overflow-y-auto'}`}>
          {renderPage()}
        </div>
      </div>
    </div>
  );
}
