export default function Services() {
  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('opacity-100', 'translate-y-0');
            entry.target.classList.remove('opacity-0', 'translate-y-6');
          }
        });
      },
      { threshold: 0.1 }
    );
    cardRefs.current.forEach((el) => el && observer.observe(el));
    return () => observer.disconnect();
  }, []);

  return (
    <section id="services" className="py-7 bg-white">
      <div className="max-w-content mx-auto px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-8">
          <h2 className="text-3xl md:text-4xl font-black text-gray-900 mb-4">보안 서비스</h2>
          <p className="text-base text-gray-500 max-w-xl mx-auto">
            해킹 전문가가 제공하는 실전 보안 서비스
          </p>
        </div>

        {/* Cards */}
        <div className="grid md:grid-cols-3 gap-6">
          {services.map((svc, i) => (
            <div
              key={svc.href}
              ref={(el) => { cardRefs.current[i] = el; }}
              className="opacity-0 translate-y-6 transition-all duration-700 bg-white border border-gray-100 rounded-2xl overflow-hidden hover:border-teal-200 hover:shadow-lg group flex flex-col"
              style={{ transitionDelay: `${i * 120}ms` }}
            >
              {/* Card top */}
              <div className="p-6 border-b border-gray-50">
                <div className="flex items-center gap-3 mb-4">
                  <div className={`w-10 h-10 flex items-center justify-center rounded-xl border ${svc.iconBg}`}>
                    <i className={`${svc.icon} text-xl ${svc.iconColor}`}></i>
                  </div>
                  <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${svc.badgeBg}`}>
                    {svc.badge}
                  </span>
                </div>
                <h3 className="text-xl font-black text-gray-900 mb-2">{svc.name}</h3>
                <p className="text-sm text-gray-600 leading-relaxed">{svc.desc}</p>
              </div>

              {/* Card body */}
              <div className="p-6 flex flex-col flex-1">
                <ul className="space-y-2.5 mb-6 flex-1">
                  {svc.features.map((f, fi) => (
                    <li key={fi} className="flex items-start gap-2 text-sm text-gray-700">
                      <i className="ri-check-line text-teal-500 flex-shrink-0 mt-0.5"></i>
                      {f}
                    </li>
                  ))}
                </ul>
                <div className="flex flex-wrap gap-1.5 mb-5">
                  {svc.tags.map((t) => (
                    <span key={t} className="text-xs px-2.5 py-1 bg-gray-100 text-gray-600 rounded-full">{t}</span>
                  ))}
                </div>
                <Link
                  to={svc.href}
                  className="text-sm font-semibold text-teal-600 hover:text-teal-700 transition-colors whitespace-nowrap cursor-pointer"
                >
                  서비스 상담 →
                </Link>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
