import { useState } from 'react';
import { POPUPS } from '../mockData';
import type { PopupItem, PopupStatus } from '../types';

const STATUS_STYLE: Record<PopupStatus, { bg: string; text: string; dot: string; label: string }> = {
  활성: { bg: 'bg-teal-50', text: 'text-teal-700', dot: 'bg-teal-500', label: '✓ Active' },
  예약: { bg: 'bg-amber-50', text: 'text-amber-700', dot: 'bg-amber-400', label: '⏱ Scheduled' },
  비활성: { bg: 'bg-gray-100', text: 'text-gray-500', dot: 'bg-gray-400', label: 'Inactive' },
};

/** 신규 팝업 코드 자동 생성: 01AA, 01AB, ... 형식 */
function generateCode(existingCodes: string[]): string {
  const PREFIX = '01';
  const ALPHA = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  for (let i = 0; i < ALPHA.length; i++) {
    for (let j = 0; j < ALPHA.length; j++) {
      const candidate = `${PREFIX}${ALPHA[i]}${ALPHA[j]}`;
      if (!existingCodes.includes(candidate)) return candidate;
    }
  }
  return `02AA`;
}

function PbModal({ item, onClose, onSave, existingCodes }: { item: PopupItem | null; onClose: () => void; onSave: (p: PopupItem) => void; existingCodes: string[] }) {
  const isNew = !item;
  const autoCode = isNew ? generateCode(existingCodes) : '';
  const [form, setForm] = useState<PopupItem>(item ?? {
    id: Date.now(), code: autoCode, type: '팝업', title: '', periodFrom: '', periodTo: '', lang: 'KR', device: ['PC'], views: 0, lastModified: new Date().toISOString().slice(0, 10), status: '비활성',
  });
  const [langs, setLangs] = useState<string[]>((item?.lang ?? 'KR').split(' · ').filter(Boolean));
  const [headline, setHeadline] = useState('');
  const [body, setBody] = useState('');
  const [btnTxt, setBtnTxt] = useState('자세히 보기');
  const [btnUrl, setBtnUrl] = useState('');

  const toggleLang = (l: string) => setLangs((prev) => prev.includes(l) ? prev.filter((x) => x !== l) : [...prev, l]);
  const toggleDevice = (d: string) => setForm((prev) => ({
    ...prev,
    device: prev.device.includes(d) ? prev.device.filter((x) => x !== d) : [...prev.device, d],
  }));

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />
      <div className="relative bg-white rounded-xl w-[860px] max-h-[90vh] flex flex-col" style={{ maxWidth: '95vw' }}>
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <div className="flex items-center gap-3">
            <span className="text-[14px] font-bold text-gray-900">{isNew ? '팝업·배너 추가' : form.title}</span>
            <span className="text-[11px] font-mono text-gray-400 bg-gray-100 px-2 py-0.5 rounded">{form.code || autoCode}</span>
            {isNew && <span className="text-[10px] text-teal-500">코드 자동 생성됨</span>}
          </div>
          <button onClick={onClose} className="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-gray-100 cursor-pointer">
            <i className="ri-close-line text-gray-500 text-lg"></i>
          </button>
        </div>
        <div className="flex flex-1 overflow-hidden">
          {/* Left */}
          <div className="flex-1 overflow-y-auto px-6 py-5 space-y-4 border-r border-gray-100">
            <div>
              <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-3">기본 정보</p>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">유형</label>
                  <select value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value as '팝업' | '배너' })} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400 cursor-pointer">
                    <option>팝업</option><option>배너</option>
                  </select>
                </div>
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">제목</label>
                  <input value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400" placeholder="팝업·배너 제목" />
                </div>
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">노출 시작일</label>
                  <input type="date" value={form.periodFrom} onChange={(e) => setForm({ ...form, periodFrom: e.target.value })} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400" />
                </div>
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">노출 종료일</label>
                  <input type="date" value={form.periodTo} onChange={(e) => setForm({ ...form, periodTo: e.target.value })} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400" />
                </div>
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">언어</label>
                  <div className="flex gap-1.5 flex-wrap">
                    {['KR', 'EN', 'JP', 'ID'].map((l) => (
                      <button key={l} onClick={() => toggleLang(l)} className={`px-2.5 py-1 rounded-lg text-[11px] font-semibold border transition-colors cursor-pointer whitespace-nowrap ${langs.includes(l) ? 'bg-[#1a1e2a] text-white border-[#1a1e2a]' : 'text-gray-500 border-gray-200 hover:border-teal-400'}`}>{l}</button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">노출 기기</label>
                  <div className="flex gap-2">
                    {['PC', 'MO'].map((d) => (
                      <label key={d} className="flex items-center gap-1.5 cursor-pointer">
                        <input type="checkbox" checked={form.device.includes(d)} onChange={() => toggleDevice(d)} />
                        <span className="text-[12px] text-gray-700">{d}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </div>
            </div>
            <div>
              <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-3">콘텐츠</p>
              <div className="space-y-3">
                <div className="border-2 border-dashed border-gray-200 rounded-lg p-6 text-center cursor-pointer hover:border-teal-400 transition-colors">
                  <i className="ri-image-add-line text-gray-300 text-2xl"></i>
                  <p className="text-[12px] text-gray-400 mt-1">클릭하거나 이미지를 드래그 <span className="text-gray-300">(JPG, PNG, GIF, WebP · 최대 5MB)</span></p>
                </div>
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">제목 텍스트</label>
                  <input value={headline} onChange={(e) => setHeadline(e.target.value)} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400" placeholder="팝업 내 헤드라인" />
                </div>
                <div>
                  <label className="text-[11px] text-gray-500 mb-1 block">본문 내용</label>
                  <textarea value={body} onChange={(e) => setBody(e.target.value)} rows={3} className="w-full border border-gray-200 rounded-lg px-2.5 py-2 text-[12px] outline-none focus:border-teal-400 resize-none" placeholder="팝업 본문 내용" />
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="text-[11px] text-gray-500 mb-1 block">버튼 텍스트</label>
                    <input value={btnTxt} onChange={(e) => setBtnTxt(e.target.value)} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400" />
                  </div>
                  <div>
                    <label className="text-[11px] text-gray-500 mb-1 block">버튼 링크</label>
                    <input value={btnUrl} onChange={(e) => setBtnUrl(e.target.value)} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400" placeholder="https://..." />
                  </div>
                </div>
              </div>
            </div>
          </div>
          {/* Right */}
          <div className="w-[220px] flex-shrink-0 px-5 py-5 space-y-5">
            <div>
              <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-3">미리보기</p>
              <div className="bg-gray-50 rounded-lg p-4 min-h-[120px] flex flex-col gap-2">
                {headline ? <p className="text-[13px] font-bold text-gray-800">{headline}</p> : <p className="text-[12px] text-gray-300 italic">제목</p>}
                {body ? <p className="text-[11px] text-gray-600">{body}</p> : <p className="text-[11px] text-gray-300 italic">본문 내용</p>}
                <button className="mt-1 px-3 py-1 bg-teal-500 text-white text-[11px] rounded-lg self-start whitespace-nowrap">{btnTxt}</button>
              </div>
            </div>
            <div>
              <label className="text-[11px] text-gray-500 mb-1 block">상태</label>
              <select value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value as PopupStatus })} className="w-full border border-gray-200 rounded-lg px-2.5 py-1.5 text-[12px] outline-none focus:border-teal-400 cursor-pointer">
                <option>활성</option><option>비활성</option><option>예약</option>
              </select>
            </div>
            {!isNew && (
              <div>
                <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-2">노출 통계</p>
                <div className="space-y-1.5">
                  {[['노출수', item.views.toLocaleString()], ['클릭수', '—'], ['클릭률', '—']].map(([k, v]) => (
                    <div key={k} className="flex justify-between text-[12px]">
                      <span className="text-gray-400">{k}</span><span className="font-medium text-gray-700">{v}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
        <div className="flex items-center justify-between px-6 py-3.5 border-t border-gray-100">
          <div></div>
          <div className="flex gap-2">
            <button onClick={onClose} className="px-4 py-1.5 rounded-lg border border-gray-200 text-[12px] text-gray-600 hover:bg-gray-50 cursor-pointer whitespace-nowrap">취소</button>
            <button onClick={() => onSave({ ...form, lang: langs.join(' · ') })} className="px-4 py-1.5 rounded-lg bg-teal-500 text-white text-[12px] font-semibold hover:bg-teal-600 cursor-pointer whitespace-nowrap">저장</button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function PopupPage() {
  const [popups, setPopups] = useState<PopupItem[]>(POPUPS);
  const [typeFilter, setTypeFilter] = useState('전체');
  const [search, setSearch] = useState('');
  const [modal, setModal] = useState<PopupItem | null | undefined>(undefined);

  const filtered = popups.filter((p) => {
    if (typeFilter !== '전체' && p.type !== typeFilter) return false;
    if (search.trim()) {
      const q = search.toLowerCase();
      return p.code.toLowerCase().includes(q) || p.title.toLowerCase().includes(q);
    }
    return true;
  });

  const stats = {
    total: filtered.length,
    active: filtered.filter((p) => p.status === '활성').length,
    scheduled: filtered.filter((p) => p.status === '예약').length,
    inactive: filtered.filter((p) => p.status === '비활성').length,
  };

  const handleSave = (p: PopupItem) => {
    setPopups((prev) => prev.some((x) => x.id === p.id) ? prev.map((x) => x.id === p.id ? p : x) : [...prev, p]);
    setModal(undefined);
  };

  return (
    <div className="p-5 space-y-4">
      <div className="bg-white border border-gray-100 rounded-lg px-4 py-3 flex items-center gap-3 flex-wrap">
        <div className="flex gap-1">
          {['전체', '팝업', '배너'].map((t) => (
            <button key={t} onClick={() => setTypeFilter(t)} className={`px-3 py-1.5 rounded-lg text-[12px] font-medium transition-colors cursor-pointer whitespace-nowrap ${typeFilter === t ? 'bg-[#1a1e2a] text-white' : 'text-gray-500 hover:bg-gray-100'}`}>{t}</button>
          ))}
        </div>
        <div className="flex items-center gap-1.5 border border-gray-200 rounded-lg px-3 py-1.5">
          <i className="ri-search-line text-gray-400 text-sm"></i>
          <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="코드, 팝업명 검색" className="text-[12px] text-gray-700 outline-none w-32 placeholder:text-gray-300" />
        </div>
        <button onClick={() => setModal(null)} className="ml-auto flex items-center gap-1.5 px-3 py-1.5 bg-teal-500 text-white text-[12px] font-semibold rounded-lg hover:bg-teal-600 cursor-pointer whitespace-nowrap">
          <i className="ri-add-line text-sm"></i>팝업·배너 추가
        </button>
      </div>

      <div className="bg-white border border-gray-100 rounded-lg px-5 py-2.5 flex items-center gap-5 text-[12px] text-gray-500">
        <span>총 <strong className="text-gray-900">{stats.total}</strong>건</span>
        <span>활성 <strong className="text-teal-500">{stats.active}</strong>건</span>
        <span>예약 <strong className="text-amber-500">{stats.scheduled}</strong>건</span>
        <span>비활성 <strong className="text-gray-400">{stats.inactive}</strong>건</span>
      </div>

      <div className="bg-white border border-gray-100 rounded-lg overflow-x-auto">
        <table className="w-full" style={{ minWidth: 780 }}>
          <thead>
            <tr className="bg-gray-50/70 border-b border-gray-100">
              {['코드', '유형', '팝업·배너명', '노출 기간', '언어', '기기', '노출수', '최종 수정', '활성'].map((h) => (
                <th key={h} className="text-left px-4 py-2.5 text-[11px] font-semibold text-gray-400 whitespace-nowrap">{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map((p) => {
              const sc = STATUS_STYLE[p.status];
              return (
                <tr key={p.id} className="border-b border-gray-50 hover:bg-gray-50/60 transition-colors cursor-pointer" onClick={() => setModal(p)}>
                  <td className="px-4 py-3 text-[11px] font-mono text-teal-600 whitespace-nowrap">{p.code}</td>
                  <td className="px-4 py-3">
                    <span className="text-[11px] font-semibold px-2 py-0.5 rounded bg-sky-50 text-sky-700 whitespace-nowrap">{p.type}</span>
                  </td>
                  <td className="px-4 py-3 text-[13px] text-gray-800 whitespace-nowrap">{p.title}</td>
                  <td className="px-4 py-3 text-[11px] text-gray-500 whitespace-nowrap">{p.periodFrom} ~ {p.periodTo}</td>
                  <td className="px-4 py-3 text-[11px] text-gray-500 whitespace-nowrap">{p.lang}</td>
                  <td className="px-4 py-3">
                    <div className="flex gap-1">
                      {p.device.map((d) => <span key={d} className="text-[10px] px-1.5 py-0.5 rounded bg-gray-100 text-gray-600 whitespace-nowrap">{d}</span>)}
                    </div>
                  </td>
                  <td className="px-4 py-3 text-[12px] text-gray-600 whitespace-nowrap">{p.views.toLocaleString()}</td>
                  <td className="px-4 py-3 text-[12px] text-gray-400 whitespace-nowrap">{p.lastModified}</td>
                  <td className="px-4 py-3">
                    <span className={`inline-flex items-center gap-1.5 text-[11px] font-semibold px-2.5 py-1 rounded-full whitespace-nowrap ${sc.bg} ${sc.text}`}>
                      <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${sc.dot}`}></span>
                      {sc.label}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {modal !== undefined && <PbModal item={modal} onClose={() => setModal(undefined)} onSave={handleSave} existingCodes={popups.map((p) => p.code)} />}
    </div>
  );
}
